function Card({ children, style, accent }) {
  return <div style={{ background: C.surface, border: `1px solid ${accent ? accent + "30" : C.border}`, borderRadius: 14, padding: 16, marginBottom: 12, ...style }}>{children}</div>;
}
function SectionLabel({ children }) {
  return <div style={{ fontSize: 10, fontWeight: 800, color: C.sub, textTransform: "uppercase", letterSpacing: "1px", marginBottom: 10 }}>{children}</div>;
}
function Bar({ pct, color }) {
  return <div style={{ height: 6, borderRadius: 3, background: C.border, overflow: "hidden" }}><div style={{ height: "100%", width: `${Math.min(100, Math.max(0, pct))}%`, borderRadius: 3, background: `linear-gradient(90deg, ${color}80, ${color})`, transition: "width 0.4s" }} /></div>;
}
function Btn({ children, onClick, color, small, outline }) {
  return (
    <button onClick={onClick} style={{
      background: outline ? "transparent" : `linear-gradient(135deg, ${color}bb, ${color})`,
      border: outline ? `1.5px solid ${color}` : "none",
      borderRadius: small ? 8 : 11, color: outline ? color : "#fff",
      fontWeight: 700, fontSize: small ? 11 : 13,
      padding: small ? "6px 12px" : "11px 18px",
      cursor: "pointer", width: small ? "auto" : "100%",
    }}>{children}</button>
  );
}
function TxtInput({ value, onChange, placeholder, label, type = "text" }) {
  return (
    <div>
      {label && <div style={{ fontSize: 10, color: C.sub, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.6px", marginBottom: 4 }}>{label}</div>}
      <input type={type} value={value ?? ""} placeholder={placeholder} onChange={e => onChange(type === "number" ? (e.target.value === "" ? "" : Number(e.target.value)) : e.target.value)}
        style={{ background: C.inputBg, border: `1px solid ${C.border}`, borderRadius: 8, color: C.text, fontSize: 13, padding: "8px 10px", width: "100%", outline: "none", boxSizing: "border-box" }} />
    </div>
  );
}

// ─── EXERCISE CARD (yoga-style: checklist + expandable form guide + inspo photo) ─────
function ExerciseCard({ ex, dayColor, checked, onCheck, dayId, isFirst }) {
  const [open, setOpen] = useState(false);
  const [setsDone, setSetsDone] = useState(() => loadS(`sets-${ex.id}`, []));

  const totalSets = ex.sets;
  const doneSetCount = setsDone.length;
  const allSetsDone = totalSets > 1 ? doneSetCount >= totalSets : checked;

  const toggleSet = (i) => {
    let next;
    if (setsDone.includes(i)) { next = setsDone.filter(x => x !== i); }
    else { next = [...setsDone, i]; }
    setSetsDone(next);
    saveS(`sets-${ex.id}`, next);
    if (next.length >= totalSets) onCheck(true);
    else if (totalSets === 1 && next.length === 0) onCheck(false);
  };

  return (
    <div style={{ background: checked ? C.surface : C.surface, border: `1px solid ${checked ? dayColor + "40" : C.border}`, borderRadius: 12, marginBottom: 8, overflow: "hidden", transition: "all 0.2s" }}>
      {/* Header row — tap to expand */}
      <div style={{ display: "flex", alignItems: "center", gap: 12, padding: "12px 14px", cursor: "pointer" }} onClick={() => setOpen(o => !o)}>
        {/* Master check circle */}
        <div
          onClick={e => { e.stopPropagation(); onCheck(!checked); }}
          style={{ width: 24, height: 24, borderRadius: "50%", border: `2px solid ${checked ? dayColor : C.border}`, background: checked ? dayColor : "transparent", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, transition: "all 0.2s", cursor: "pointer" }}
        >
          {checked && <span style={{ color: "#fff", fontSize: 12, fontWeight: 700 }}>✓</span>}
        </div>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 14, fontWeight: 600, color: checked ? C.muted : C.text, textDecoration: checked ? "line-through" : "none" }}>{ex.name}</div>
          <div style={{ fontSize: 11, color: C.muted, marginTop: 1 }}>
            {ex.sets > 1 ? `${ex.sets} sets · ` : ""}{ex.reps}
            {ex.sets > 1 && <span style={{ color: dayColor, marginLeft: 8 }}>{doneSetCount}/{ex.sets} sets</span>}
          </div>
        </div>
        {/* Set dots */}
        {ex.sets > 1 && (
          <div style={{ display: "flex", gap: 4, flexShrink: 0 }}>
            {Array.from({ length: ex.sets }).map((_, i) => (
              <div
                key={i}
                onClick={e => { e.stopPropagation(); toggleSet(i); }}
                style={{ width: 12, height: 12, borderRadius: "50%", border: `2px solid ${dayColor}`, background: setsDone.includes(i) ? dayColor : "transparent", cursor: "pointer", transition: "all 0.15s" }}
              />
            ))}
          </div>
        )}
        <div style={{ fontSize: 10, color: C.muted, flexShrink: 0 }}>{open ? "▲" : "▼"}</div>
      </div>

      {/* Expanded form guide */}
      {open && ex.formGuide && (
        <div style={{ borderTop: `1px solid ${C.inputBg}`, padding: "14px 14px 16px" }}>

          {/* Start / End */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 12 }}>
            <div style={{ background: `${dayColor}0f`, borderRadius: 8, padding: 10 }}>
              <div style={{ fontSize: 9, fontWeight: 800, color: dayColor, textTransform: "uppercase", letterSpacing: "0.8px", marginBottom: 5 }}>Start Position</div>
              <div style={{ fontSize: 11, color: C.sub, lineHeight: 1.6 }}>{ex.formGuide.start}</div>
            </div>
            <div style={{ background: `${dayColor}0f`, borderRadius: 8, padding: 10 }}>
              <div style={{ fontSize: 9, fontWeight: 800, color: dayColor, textTransform: "uppercase", letterSpacing: "0.8px", marginBottom: 5 }}>End Position</div>
              <div style={{ fontSize: 11, color: C.sub, lineHeight: 1.6 }}>{ex.formGuide.end}</div>
            </div>
          </div>

          {/* Cues */}
          <div style={{ marginBottom: 10 }}>
            <div style={{ fontSize: 9, fontWeight: 800, color: C.sub, textTransform: "uppercase", letterSpacing: "0.8px", marginBottom: 6 }}>Form Cues</div>
            {ex.formGuide.cues.map((cue, i) => (
              <div key={i} style={{ display: "flex", gap: 8, marginBottom: 5 }}>
                <div style={{ width: 4, height: 4, borderRadius: "50%", background: dayColor, flexShrink: 0, marginTop: 5 }} />
                <div style={{ fontSize: 11, color: C.sub, lineHeight: 1.6 }}>{cue}</div>
              </div>
            ))}
          </div>

          {/* Common mistake */}
          <div style={{ background: `${C.amber}12`, border: `1px solid ${C.amber}30`, borderRadius: 8, padding: 10, marginBottom: 10 }}>
            <div style={{ fontSize: 9, fontWeight: 800, color: C.amber, textTransform: "uppercase", letterSpacing: "0.8px", marginBottom: 4 }}>⚠ Common Mistake</div>
            <div style={{ fontSize: 11, color: C.sub, lineHeight: 1.5 }}>{ex.formGuide.mistake}</div>
          </div>

          {/* Muscles */}
          <div style={{ display: "flex", flexWrap: "wrap", gap: 5 }}>
            {ex.formGuide.muscles.map(m => (
              <span key={m} style={{ fontSize: 10, color: dayColor, background: `${dayColor}18`, borderRadius: 6, padding: "3px 8px", fontWeight: 600 }}>{m}</span>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// ─── FOOD LOG COMPONENT ────────────────────────────────────────────────────────
const USDA_KEY = "mIScJzOwrIULy3vJd4oYws7Iiu15DKs1VHhAaO1U";

function getUsdaMacros(food) {
  const nutrients = food.foodNutrients || [];
  const get = (id) => {
    const n = nutrients.find(n => n.nutrientId === id || n.number === String(id));
    return n ? Math.round(n.value || 0) : 0;
  };
  // Energy: 1008, Protein: 1003, Carbs: 1005, Fat: 1004
  return {
    calories: get(1008),
    protein: get(1003),
    carbs: get(1005),
    fat: get(1004),
  };
}

function FoodLogger({ foodLog, setFoodLog, onTotalsChange }) {
  const [searchQ, setSearchQ] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [pending, setPending] = useState(null);
  const [pendingServings, setPendingServings] = useState(1);
  const [manualMode, setManualMode] = useState(false);
  const [manual, setManual] = useState({ name: "", calories: "", protein: "", carbs: "", fat: "" });
  const [loading, setLoading] = useState(false);
  const [usdaError, setUsdaError] = useState("");

  useEffect(() => {
    if (!searchQ.trim()) { setSearchResults([]); setUsdaError(""); return; }
    // First show local results instantly
    const q = searchQ.toLowerCase();
    const local = FOODS_DB.filter(f => f.name.toLowerCase().includes(q)).slice(0, 3);
    setSearchResults(local);
    // Then fetch USDA
    const timer = setTimeout(async () => {
      setLoading(true);
      setUsdaError("");
      try {
        const res = await fetch(`https://api.nal.usda.gov/fdc/v1/foods/search?query=${encodeURIComponent(searchQ)}&pageSize=8&api_key=${USDA_KEY}`);
        const data = await res.json();
        if (data.foods && data.foods.length > 0) {
          const usdaResults = data.foods.map(f => {
            const macros = getUsdaMacros(f);
            return {
              name: f.description.slice(0, 50),
              ...macros,
              category: macros.calories > 400 ? "junk" : macros.protein > 15 ? "protein" : macros.carbs > 20 ? "carb" : "other",
              delayDays: 0,
              usda: true,
            };
          }).filter(f => f.calories > 0);
          setSearchResults([...local, ...usdaResults].slice(0, 10));
        }
      } catch (e) {
        setUsdaError("USDA search unavailable — showing local results");
      } finally {
        setLoading(false);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [searchQ]);

  const addPending = () => {
    if (!pending) return;
    const s = parseFloat(pendingServings) || 1;
    const entry = {
      name: `${pending.name}${s !== 1 ? ` (×${s})` : ""}`,
      protein: Math.round(pending.protein * s),
      calories: Math.round(pending.calories * s),
      carbs: Math.round((pending.carbs || 0) * s),
      fat: Math.round((pending.fat || 0) * s),
      category: pending.category,
      delayDays: pending.delayDays ? +(pending.delayDays * s).toFixed(2) : 0,
    };
    const updated = [...foodLog, entry];
    setFoodLog(updated);
    saveS(`food-${getTodayKey()}`, updated);
    onTotalsChange(updated);
    setPending(null); setSearchQ(""); setSearchResults([]); setPendingServings(1);
  };

  const addManual = () => {
    if (!manual.name && !manual.calories) return;
    const entry = {
      name: manual.name || "Custom food",
      protein: Number(manual.protein) || 0,
      calories: Number(manual.calories) || 0,
      carbs: Number(manual.carbs) || 0,
      fat: Number(manual.fat) || 0,
      category: "manual",
      delayDays: 0,
    };
    const updated = [...foodLog, entry];
    setFoodLog(updated);
    saveS(`food-${getTodayKey()}`, updated);
    onTotalsChange(updated);
    setManual({ name: "", calories: "", protein: "", carbs: "", fat: "" });
    setManualMode(false);
  };

  const removeEntry = (idx) => {
    const updated = foodLog.filter((_, i) => i !== idx);
    setFoodLog(updated);
    saveS(`food-${getTodayKey()}`, updated);
    onTotalsChange(updated);
  };

  const totals = foodLog.reduce((a, f) => ({ protein: a.protein + f.protein, calories: a.calories + f.calories, carbs: a.carbs + (f.carbs || 0), fat: a.fat + (f.fat || 0) }), { protein: 0, calories: 0, carbs: 0, fat: 0 });

  return (
    <div>
      {/* Search / manual toggle */}
      <div style={{ display: "flex", gap: 8, marginBottom: 10 }}>
        <button onClick={() => { setManualMode(false); setPending(null); }} style={{ flex: 1, padding: "8px 0", borderRadius: 8, fontSize: 12, fontWeight: 700, cursor: "pointer", background: !manualMode ? `${C.sage}22` : "transparent", border: `1.5px solid ${!manualMode ? C.sage : C.border}`, color: !manualMode ? C.sage : C.muted }}>Search Foods</button>
        <button onClick={() => { setManualMode(true); setPending(null); setSearchQ(""); setSearchResults([]); }} style={{ flex: 1, padding: "8px 0", borderRadius: 8, fontSize: 12, fontWeight: 700, cursor: "pointer", background: manualMode ? `${C.plum}22` : "transparent", border: `1.5px solid ${manualMode ? C.plum : C.border}`, color: manualMode ? C.plum : C.muted }}>Manual Entry</button>
      </div>

      {/* SEARCH MODE */}
      {!manualMode && (
        <div>
          <TxtInput value={searchQ} onChange={setSearchQ} placeholder='Search any food — powered by USDA 🔍' />
          {loading && <div style={{ fontSize: 10, color: C.sub, padding: "6px 2px" }}>Searching USDA database…</div>}
          {usdaError && <div style={{ fontSize: 10, color: C.amber, padding: "4px 2px" }}>{usdaError}</div>}
          {searchResults.length > 0 && !pending && (
            <div style={{ marginTop: 6, background: "#1a1028", border: `1px solid ${C.border}`, borderRadius: 10, overflow: "hidden" }}>
              {searchResults.map((f, i) => (
                <div key={i} onClick={() => { setPending(f); setSearchQ(""); setSearchResults([]); setPendingServings(1); }}
                  style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 14px", borderBottom: i < searchResults.length - 1 ? `1px solid ${C.border}` : "none", cursor: "pointer" }}>
                  <div style={{ flex: 1, marginRight: 8 }}>
                    <div style={{ fontSize: 13, color: C.text }}>{f.name}</div>
                    <div style={{ fontSize: 10, color: C.muted }}>{f.protein}g protein · {f.calories} cal · {f.carbs}g carbs</div>
                  </div>
                  <span style={{ fontSize: 9, fontWeight: 700, color: f.usda ? C.dotBlue : f.category === "junk" ? C.amber : C.sage, background: f.usda ? "rgba(107,230,247,0.1)" : f.category === "junk" ? `${C.amber}18` : `${C.sage}18`, borderRadius: 5, padding: "2px 7px", flexShrink: 0 }}>{f.usda ? "USDA" : f.category}</span>
                </div>
              ))}
            </div>
          )}

          {/* Pending: configure servings then add */}
          {pending && (
            <div style={{ marginTop: 8, background: `${C.sage}0f`, border: `1px solid ${C.sage}30`, borderRadius: 10, padding: 12 }}>
              <div style={{ fontSize: 13, fontWeight: 700, color: C.text, marginBottom: 2 }}>{pending.name}</div>
              <div style={{ fontSize: 11, color: C.muted, marginBottom: 10 }}>{pending.protein}g protein · {pending.calories} cal per serving</div>
              <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}>
                <div style={{ flex: 1 }}>
                  <TxtInput label="Servings" type="number" value={pendingServings} onChange={v => setPendingServings(v || 1)} placeholder="1" />
                </div>
                <div style={{ flex: 2, fontSize: 11, color: C.sage, paddingTop: 18 }}>
                  = {Math.round(pending.protein * (parseFloat(pendingServings) || 1))}g protein · {Math.round(pending.calories * (parseFloat(pendingServings) || 1))} cal
                  {pending.delayDays ? <span style={{ color: C.amber }}> · +{+(pending.delayDays * (parseFloat(pendingServings) || 1)).toFixed(1)}d delay</span> : ""}
                </div>
              </div>
              <div style={{ display: "flex", gap: 8 }}>
                <Btn onClick={addPending} color={C.sage} small>Add to Log</Btn>
                <Btn onClick={() => { setPending(null); setSearchQ(""); }} color={C.muted} small outline>Cancel</Btn>
              </div>
            </div>
          )}
        </div>
      )}

      {/* MANUAL MODE */}
      {manualMode && (
        <div style={{ background: `${C.plum}0f`, border: `1px solid ${C.plum}25`, borderRadius: 10, padding: 12 }}>
          <TxtInput label="Food name" value={manual.name} onChange={v => setManual(p => ({ ...p, name: v }))} placeholder="e.g. Mom's rice and beans" />
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginTop: 8 }}>
            <TxtInput label="Calories" type="number" value={manual.calories} onChange={v => setManual(p => ({ ...p, calories: v }))} placeholder="0" />
            <TxtInput label="Protein (g)" type="number" value={manual.protein} onChange={v => setManual(p => ({ ...p, protein: v }))} placeholder="0" />
            <TxtInput label="Carbs (g)" type="number" value={manual.carbs} onChange={v => setManual(p => ({ ...p, carbs: v }))} placeholder="0" />
            <TxtInput label="Fat (g)" type="number" value={manual.fat} onChange={v => setManual(p => ({ ...p, fat: v }))} placeholder="0" />
          </div>
          <div style={{ display: "flex", gap: 8, marginTop: 10 }}>
            <Btn onClick={addManual} color={C.plum} small>Add Entry</Btn>
            <Btn onClick={() => { setManualMode(false); setManual({ name: "", calories: "", protein: "", carbs: "", fat: "" }); }} color={C.muted} small outline>Cancel</Btn>
          </div>
        </div>
      )}

      {/* Food log list */}
      {foodLog.length > 0 && (
        <div style={{ marginTop: 14 }}>
          <SectionLabel>Today's Log</SectionLabel>
          {foodLog.map((f, i) => (
            <div key={i} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 0", borderBottom: `1px solid ${C.border}` }}>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 12, color: C.text, fontWeight: 500 }}>{f.name}</div>
                <div style={{ fontSize: 10, color: C.muted, marginTop: 1 }}>
                  {f.protein}g protein · {f.calories} cal · {f.carbs || 0}g carbs · {f.fat || 0}g fat
                  {f.delayDays > 0 && <span style={{ color: C.amber }}> · +{f.delayDays}d delay</span>}
                </div>
              </div>
              <button onClick={() => removeEntry(i)} style={{ fontSize: 14, color: C.muted, background: "none", border: "none", cursor: "pointer", padding: "0 6px" }}>✕</button>
            </div>
          ))}
          {/* Totals row */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr 1fr", gap: 6, marginTop: 10 }}>
            {[
              { label: "Protein", val: `${totals.protein}g`, color: C.sage },
              { label: "Calories", val: totals.calories, color: C.amber },
              { label: "Carbs", val: `${totals.carbs}g`, color: C.plum },
              { label: "Fat", val: `${totals.fat}g`, color: C.rose },
            ].map(({ label, val, color }) => (
              <div key={label} style={{ textAlign: "center", background: `${color}10`, borderRadius: 8, padding: "6px 4px" }}>
                <div style={{ fontSize: 12, fontWeight: 800, color }}>{val}</div>
                <div style={{ fontSize: 9, color: C.muted, marginTop: 1 }}>{label}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// ─── WEIGHT SECTION ───────────────────────────────────────────────────────────
function WeightSection({ weightLog, setWeightLog }) {
  const [inputW, setInputW] = useState("");
  const [inputNote, setInputNote] = useState("");
  const latest = weightLog.length > 0 ? parseFloat(weightLog[0].weight) : START_WEIGHT;
  const lost = +(START_WEIGHT - latest).toFixed(1);
  const remaining = +(latest - GOAL_WEIGHT).toFixed(1);
  const pct = Math.min(100, Math.max(0, Math.round(((START_WEIGHT - latest) / (START_WEIGHT - GOAL_WEIGHT)) * 100)));
  const targetDate = calcTargetDate(latest);
  const save = () => {
    if (!inputW) return;
    const updated = [{ date: getTodayKey(), weight: inputW, note: inputNote }, ...weightLog].slice(0, 30);
    setWeightLog(updated); saveS("weight-log", updated); setInputW(""); setInputNote("");
  };
  const chartWts = [...weightLog].reverse().slice(-10);
  return (
    <>
      <Card accent={C.rose}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 14 }}>
          <div>
            <SectionLabel>Current Weight</SectionLabel>
            <div style={{ fontSize: 32, fontWeight: 800, color: C.rose, letterSpacing: "-1px" }}>{latest}<span style={{ fontSize: 14, color: C.muted, fontWeight: 400 }}> lbs</span></div>
            <div style={{ fontSize: 11, color: C.sub, marginTop: 3 }}>{lost > 0 ? `↓ ${lost} lbs lost` : "Starting point"} · {remaining > 0 ? `${remaining} to go` : "Goal reached! 🎉"}</div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: 10, color: C.muted }}>Goal</div>
            <div style={{ fontSize: 26, fontWeight: 800, color: C.sage }}>{GOAL_WEIGHT}<span style={{ fontSize: 11, color: C.muted }}> lbs</span></div>
            {targetDate && (<>
              <div style={{ fontSize: 10, color: C.muted, marginTop: 4 }}>{fmtDate(targetDate)}</div>
              <div style={{ fontSize: 10, color: C.plum, fontWeight: 700 }}>{weeksAway(targetDate)}</div>
            </>)}
          </div>
        </div>
        <Bar pct={pct} color={C.rose} />
        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 9, color: C.muted, marginTop: 4 }}>
          <span>{START_WEIGHT} lbs</span><span style={{ color: C.rose, fontWeight: 700 }}>{pct}% there</span><span>{GOAL_WEIGHT} lbs</span>
        </div>
        <div style={{ marginTop: 10, padding: "8px 10px", background: "rgba(123,191,160,0.08)", borderRadius: 8, fontSize: 11, color: C.sub, lineHeight: 1.6 }}>
          ✦ Your real goal is <span style={{ color: C.text }}>toned curves</span> — you may only lose 10 lbs but look dramatically different as fat becomes muscle. The scale is one signal, not the whole story.
        </div>
      </Card>
      <Card>
        <SectionLabel>Log Today's Weight</SectionLabel>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 2fr", gap: 8, marginBottom: 10 }}>
          <TxtInput label="Weight (lbs)" type="number" value={inputW} onChange={setInputW} placeholder="e.g. 148" />
          <TxtInput label="Note" value={inputNote} onChange={setInputNote} placeholder="feeling strong, bloated, etc." />
        </div>
        <Btn onClick={save} color={C.rose}>Save Entry</Btn>
      </Card>
      {chartWts.length >= 2 && (
        <Card>
          <SectionLabel>Weight Trend</SectionLabel>
          <svg width="100%" height="90" viewBox="0 0 320 90" preserveAspectRatio="none">
            {(() => {
              const ws = chartWts.map(e => parseFloat(e.weight));
              const mn = Math.min(...ws) - 1, mx = Math.max(...ws) + 1;
              const pts = ws.map((w, i) => ({ x: 10 + (i / (ws.length - 1)) * 300, y: 75 - ((w - mn) / (mx - mn)) * 62 }));
              const area = `M${pts[0].x},80 ` + pts.map(p => `L${p.x},${p.y}`).join(" ") + ` L${pts[pts.length - 1].x},80 Z`;
              const line = pts.map((p, i) => `${i === 0 ? "M" : "L"}${p.x},${p.y}`).join(" ");
              return (<>
                <defs><linearGradient id="wg" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={C.rose} stopOpacity="0.3" /><stop offset="100%" stopColor={C.rose} stopOpacity="0" /></linearGradient></defs>
                <path d={area} fill="url(#wg)" /><path d={line} stroke={C.rose} strokeWidth="2" fill="none" />
                {pts.map((p, i) => (<g key={i}><circle cx={p.x} cy={p.y} r={3} fill={C.rose} /><text x={p.x} y={p.y - 7} textAnchor="middle" fontSize="8" fill={C.muted}>{ws[i]}</text></g>))}
              </>);
            })()}
          </svg>
        </Card>
      )}
      {weightLog.length > 0 && (
        <Card>
          <SectionLabel>History</SectionLabel>
          {weightLog.slice(0, 8).map((e, i) => (
            <div key={i} style={{ display: "flex", justifyContent: "space-between", padding: "7px 0", borderBottom: i < Math.min(weightLog.length, 8) - 1 ? `1px solid ${C.border}` : "none", fontSize: 12 }}>
              <span style={{ color: C.muted }}>{e.date}</span>
              <span style={{ color: C.rose, fontWeight: 700 }}>{e.weight} lbs</span>
              {e.note && <span style={{ color: C.sub, fontSize: 11 }}>{e.note}</span>}
            </div>
          ))}
        </Card>
      )}
    </>
  );
}

// ─── YOGA TAB ─────────────────────────────────────────────────────────────────
function YogaTab({ markTodayDots }) {
  const todayKey = getTodayKey();
  const [activeSection, setActiveSection] = useState("tos");
  const [expandedSeq, setExpandedSeq] = useState(null);
  const [completed, setCompleted] = useState(() => loadS(`yoga-${todayKey}`, {}));
  const [sessions, setSessions] = useState(() => loadS(`yoga-sessions-${todayKey}`, {}));
  const [timerActive, setTimerActive] = useState(null);
  const [timerSec, setTimerSec] = useState(0);
  const section = YOGA_SECTIONS.find(s => s.id === activeSection);
  const toggle = key => {
    const updated = { ...completed, [key]: !completed[key] };
    setCompleted(updated);
    saveS(`yoga-${todayKey}`, updated);
    // Count total poses done today across ALL sections for streak purposes
    const totalDoneToday = Object.values(updated).filter(Boolean).length;
    if (totalDoneToday >= 5) {
      markTodayDots && markTodayDots({ yoga: true });
    }
  };

  const doneCount = section ? section.sequences.filter((_, i) => completed[`${activeSection}-${i}`]).length : 0;
  const totalCount = section ? section.sequences.length : 0;
  const pct = totalCount > 0 ? Math.round((doneCount / totalCount) * 100) : 0;
  const circ = 2 * Math.PI * 16;

  React.useEffect(() => {
    if (timerActive === null) return;
    if (timerSec <= 0) { setTimerActive(null); return; }
    const t = setTimeout(() => setTimerSec(s => s - 1), 1000);
    return () => clearTimeout(t);
  }, [timerActive, timerSec]);

  const startTimer = (secs, id) => { setTimerActive(id); setTimerSec(secs); };

  return (
    <div style={{ padding: "14px 14px" }}>
      {/* Pill tabs */}
      <div style={{ display: "flex", gap: 6, overflowX: "auto", marginBottom: 14, paddingBottom: 2 }}>
        {YOGA_SECTIONS.map(s => (
          <button key={s.id} onClick={() => { setActiveSection(s.id); setExpandedSeq(null); }} style={{ flexShrink: 0, padding: "7px 13px", borderRadius: 20, fontSize: 11, fontWeight: 700, cursor: "pointer", border: activeSection === s.id ? `2px solid ${s.color}` : `2px solid ${C.border}`, background: activeSection === s.id ? `${s.color}22` : C.surface, color: activeSection === s.id ? s.color : C.muted, fontFamily: "inherit" }}>
            {s.emoji} {s.label}
          </button>
        ))}
      </div>

      {/* Section header with ring */}
      {section && (
        <div style={{ background: `linear-gradient(135deg, ${section.color}14, rgba(160,124,192,0.06))`, border: `1px solid ${section.color}30`, borderRadius: 14, padding: "13px 14px", marginBottom: 12, display: "flex", alignItems: "center", gap: 14 }}>
          <svg width="44" height="44" viewBox="0 0 44 44" style={{ flexShrink: 0 }}>
            <circle cx="22" cy="22" r="16" fill="none" stroke={C.border} strokeWidth="4"/>
            <circle cx="22" cy="22" r="16" fill="none" stroke={section.color} strokeWidth="4"
              strokeDasharray={circ} strokeDashoffset={circ * (1 - pct / 100)} strokeLinecap="round"
              transform="rotate(-90 22 22)"/>
            <text x="22" y="25" textAnchor="middle" fontSize="9" fontWeight="800" fill="#f0e8f5">{doneCount}/{totalCount}</text>
          </svg>
          <div>
            <div style={{ fontSize: 12, fontWeight: 700, color: section.color, marginBottom: 3 }}>{section.emoji} {section.label}</div>
            <div style={{ fontSize: 10, color: C.sub, lineHeight: 1.5 }}>{section.description}</div>
          </div>
        </div>
      )}
      {/* Intro card */}
      <div style={{ background: `${section.color}0d`, border: `1px solid ${section.color}25`, borderRadius: 12, padding: "11px 14px", marginBottom: 12 }}>
        <div style={{ fontSize: 11, color: C.sub, lineHeight: 1.7 }}>{section.intro}</div>
      </div>

      {/* Pose cards — zen style */}
      {section.sequences.map((seq, i) => {
        const key = `${activeSection}-${i}`;
        const done = completed[key];
        const open = expandedSeq === key;
        const isTimerRunning = timerActive === key;
        const POSE_EMOJIS = ["🧘","🙆","🚪","🧊","🦋","🌊","🫁","☁️","🌿","✨"];
        return (
          <div key={i} style={{ background: done ? "rgba(169,191,83,0.06)" : open ? `${section.color}08` : C.surface, border: `1px solid ${done ? "rgba(169,191,83,0.25)" : open ? `${section.color}35` : C.border}`, borderRadius: 13, marginBottom: 8, overflow: "hidden", transition: "all 0.2s" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "12px 13px", cursor: "pointer" }} onClick={() => setExpandedSeq(open ? null : key)}>
              {/* Pose icon */}
              <div style={{ width: 36, height: 36, borderRadius: 10, background: done ? "rgba(169,191,83,0.15)" : `${section.color}18`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>
                {done ? "✓" : POSE_EMOJIS[i % POSE_EMOJIS.length]}
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 13, fontWeight: 700, color: done ? C.sub : C.text, textDecoration: done ? "line-through" : "none" }}>{seq.name}</div>
                <div style={{ fontSize: 9, color: C.sub, marginTop: 2 }}>{seq.duration}</div>
              </div>
              {/* Check button */}
              <button onClick={e => { e.stopPropagation(); toggle(key); }} style={{ width: 30, height: 30, borderRadius: 8, border: `1.5px solid ${done ? "rgba(169,191,83,0.5)" : C.border}`, background: done ? "rgba(169,191,83,0.18)" : "transparent", color: done ? C.dotGreen : C.muted, fontSize: 13, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, fontFamily: "inherit" }}>{done ? "✓" : "○"}</button>
              <div style={{ fontSize: 9, color: C.muted, marginLeft: 2 }}>{open ? "▲" : "▼"}</div>
            </div>

            {open && (
              <div style={{ borderTop: `1px solid ${C.border}`, padding: "12px 13px 14px" }}>
                <ol style={{ margin: 0, paddingLeft: 16, marginBottom: 10 }}>
                  {seq.steps.map((step, si) => (
                    <li key={si} style={{ fontSize: 12, color: C.sub, marginBottom: 6, lineHeight: 1.6 }}>{step}</li>
                  ))}
                </ol>
                {seq.caution && (
                  <div style={{ fontSize: 11, color: C.amber, background: `${C.amber}12`, borderRadius: 8, padding: "7px 10px", lineHeight: 1.5, marginBottom: 10 }}>⚠ {seq.caution}</div>
                )}
                {/* Timer */}
                {isTimerRunning ? (
                  <div style={{ padding: "10px 12px", borderRadius: 9, background: `${section.color}18`, border: `1px solid ${section.color}40`, display: "flex", alignItems: "center", justifyContent: "center", gap: 10, marginBottom: 7 }}>
                    <div style={{ fontSize: 20, fontWeight: 800, color: section.color, fontVariantNumeric: "tabular-nums" }}>{Math.floor(timerSec/60)}:{String(timerSec%60).padStart(2,"0")}</div>
                    <button onClick={() => setTimerActive(null)} style={{ fontSize: 10, color: C.muted, background: C.border, border: "none", borderRadius: 6, padding: "4px 10px", cursor: "pointer", fontFamily: "inherit" }}>Stop</button>
                  </div>
                ) : (
                  <div style={{ display: "flex", gap: 6, marginBottom: 7 }}>
                    {[30, 60, 90].map(secs => (
                      <button key={secs} onClick={() => startTimer(secs, key)} style={{ flex: 1, padding: "8px 4px", borderRadius: 9, border: `1px solid ${section.color}40`, background: `${section.color}12`, color: section.color, fontSize: 11, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>▶ {secs}s</button>
                    ))}
                  </div>
                )}
                <div style={{ display: "flex" }}>
                  <button onClick={() => toggle(key)} style={{ width: "100%", padding: "8px 14px", borderRadius: 9, border: "1px solid rgba(169,191,83,0.3)", background: "rgba(169,191,83,0.1)", color: C.dotGreen, fontSize: 11, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>{done ? "Undo" : "✓ Done"}</button>
                </div>
              </div>
            )}
          </div>
        );
      })}

      {/* Session complete button */}
      {pct === 100 && (
        <div style={{ display: "flex", flexDirection: "column", gap: 8, marginTop: 4 }}>
          <button onClick={() => {
            markTodayDots && markTodayDots({ yoga: true });
            const updated = { ...sessions, [activeSection]: (sessions[activeSection] || 0) + 1 };
            setSessions(updated);
            saveS(`yoga-sessions-${todayKey}`, updated);
          }} style={{ width: "100%", padding: 12, borderRadius: 12, border: "none", background: `linear-gradient(135deg, ${section.color}, #A07CC0)`, color: "#fff", fontSize: 13, fontWeight: 800, cursor: "pointer", fontFamily: "inherit" }}>
            🌸 Session Complete! {sessions[activeSection] > 0 ? `(${sessions[activeSection] + 1} today)` : ""}
          </button>
          {sessions[activeSection] > 0 && (
            <button onClick={() => {
              // Reset this section's completed poses for a fresh session
              const cleared = Object.fromEntries(Object.entries(completed).filter(([k]) => !k.startsWith(activeSection)));
              setCompleted(cleared);
              saveS(`yoga-${todayKey}`, cleared);
            }} style={{ width: "100%", padding: 10, borderRadius: 12, border: `1px solid ${section.color}40`, background: `${section.color}10`, color: section.color, fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>
              🔄 Log 2nd session
            </button>
          )}
        </div>
      )}

      {/* Log extra session even if not complete */}
      {pct < 100 && sessions[activeSection] > 0 && (
        <button onClick={() => {
          const cleared = Object.fromEntries(Object.entries(completed).filter(([k]) => !k.startsWith(activeSection)));
          setCompleted(cleared);
          saveS(`yoga-${todayKey}`, cleared);
        }} style={{ width: "100%", marginTop: 4, padding: 10, borderRadius: 12, border: `1px solid ${section.color}40`, background: `${section.color}10`, color: section.color, fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>
          🔄 Log 2nd session ({sessions[activeSection]} done today)
        </button>
      )}

      {/* Sessions done today indicator */}
      {sessions[activeSection] > 0 && (
        <div style={{ textAlign: "center", marginTop: 8, fontSize: 10, color: section.color, fontWeight: 700 }}>
          ✓ {sessions[activeSection]} session{sessions[activeSection] > 1 ? "s" : ""} logged today
        </div>
      )}
    </div>
  );
}

// ─── MAIN APP ─────────────────────────────────────────────────────────────────
function HomeTab({ weeklyWorkouts, weeklyHistory, foodTotals, waterOz, dailyStats, weightLog, setActiveTab }) {
  const [slide, setSlide] = useState(0);
  const [weather, setWeather] = useState(null);
  const CAROUSEL = [
    { src: "/images/IMG_7875.jpeg", pos: "center 40%", quote: '"She is fierce. She is strong. She is her own goal."' },
    { src: "/images/IMG_7872.jpeg", pos: "center 20%", quote: '"Every rep brings you closer to her."' },
    { src: "/images/IMG_7876.jpeg", pos: "center 30%", quote: '"Discipline is choosing yourself every single day."' },
    { src: "/images/IMG_9299.JPG",  pos: "center 30%", quote: '"The woman you\'re becoming will cost you old habits."' },
    { src: "/images/IMG_9302.JPG",  pos: "center 25%", quote: '"Glow different. Not harder."' },
    { src: "/images/IMG_9300.JPG",  pos: "center 20%", quote: '"She didn\'t just wish — she got to work."' },
  ];
  useEffect(() => {
    const t = setInterval(() => setSlide(s => (s + 1) % CAROUSEL.length), 3800);
    return () => clearInterval(t);
  }, []);

  // Fetch weather via free Open-Meteo API using device location
  useEffect(() => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition(async (pos) => {
      try {
        const { latitude, longitude } = pos.coords;
        const res = await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current=temperature_2m,weather_code&temperature_unit=fahrenheit`);
        const data = await res.json();
        if (data.current) {
          setWeather({ temp: Math.round(data.current.temperature_2m), code: data.current.weather_code });
        }
      } catch {}
    }, () => {}, { timeout: 3000 });
  }, []);

  const latest = weightLog.length > 0 ? parseFloat(weightLog[0].weight) : START_WEIGHT;
  const remaining = +(latest - GOAL_WEIGHT).toFixed(1);
  const pct = Math.min(100, Math.max(0, Math.round(((START_WEIGHT - latest) / (START_WEIGHT - GOAL_WEIGHT)) * 100)));
  const td = calcTargetDate(latest);

  const workoutsDone = Object.values(weeklyWorkouts).filter(Boolean).length;
  const now = new Date();
  const hour = now.getHours();
  const dayOfWeek = now.getDay(); // 0 = Sun
  const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
  const timeGreeting = hour < 12 ? "Good morning" : hour < 17 ? "Good afternoon" : "Good evening";

  const isWeatherGood = weather && weather.code <= 3 && weather.temp >= 55 && weather.temp <= 85;
  const isHot = weather && weather.temp >= 85;
  const isCold = weather && weather.temp <= 40;
  const isRainy = weather && weather.code >= 51 && weather.code <= 82;

  // Build prioritized nudge list, pick best 1-2
  const nudges = [];
  if (workoutsDone >= 5) nudges.push({ p: 10, msg: "You've hit all 5 workouts this week — incredible consistency 🔥" });
  else if (workoutsDone > 0 && workoutsDone < 5) nudges.push({ p: 6, msg: `You've hit ${workoutsDone}/5 workouts this week — keep the momentum going 💪` });
  else if (workoutsDone === 0 && dayOfWeek >= 2) nudges.push({ p: 8, msg: "No workouts logged yet this week — today's a great day to start 🎀" });

  if (waterOz < 30 && hour >= 14) nudges.push({ p: 9, msg: `You're only at ${waterOz}oz of water — let's catch up 💧` });
  else if (waterOz >= WATER_GOAL_OZ) nudges.push({ p: 4, msg: "Water goal hit for today — amazing 💙" });

  if (dailyStats.steps < 3000 && hour >= 15) nudges.push({ p: 7, msg: "Steps are low today — a short walk could help hit your goal 👟" });

  if (isWeatherGood && dailyStats.steps < STEPS_GOAL) nudges.push({ p: 8, msg: `It's ${weather.temp}° and clear outside — perfect for a walk or hike ☀️` });
  if (isHot) nudges.push({ p: 7, msg: `It's ${weather.temp}° today — drink extra water and take it easy outside 🌡️` });
  if (isRainy) nudges.push({ p: 5, msg: "Rainy day — perfect excuse to stay in and crush your workout ☔" });
  if (isCold) nudges.push({ p: 5, msg: `It's ${weather.temp}° out there — bundle up if you're heading outside 🧣` });

  if (isWeekend) nudges.push({ p: 3, msg: "Weekend recovery — stretch, hydrate, and refuel 🌿" });

  nudges.sort((a, b) => b.p - a.p);
  const topNudges = nudges.slice(0, 2);

  return (
    <div>
      <div style={{ position: "relative", height: 380, overflow: "hidden" }}>
        {CAROUSEL.map((s, i) => (
          <div key={i} style={{ position: "absolute", inset: 0, opacity: i === slide ? 1 : 0, transition: "opacity 1.1s ease" }}>
            <img src={s.src} alt="inspo" style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: s.pos, display: "block" }} />
            <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to bottom, rgba(19,13,26,0.05) 0%, rgba(19,13,26,0) 25%, rgba(19,13,26,0.6) 65%, rgba(19,13,26,1) 100%)" }} />
            <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, padding: "0 18px 18px" }}>
              <div style={{ fontSize: 15, fontWeight: 800, color: "#fff", lineHeight: 1.38, textShadow: "0 2px 14px rgba(0,0,0,0.6)", marginBottom: 14 }}>{s.quote}</div>
              <div style={{ display: "flex", gap: 5 }}>
                {CAROUSEL.map((_, j) => (
                  <div key={j} onClick={() => setSlide(j)} style={{ cursor: "pointer", height: 5, borderRadius: 3, background: j === slide ? C.dotPurple : C.border, transition: "all 0.35s", width: j === slide ? 20 : 5 }} />
                ))}
              </div>
            </div>
          </div>
        ))}
      </div>
      <div style={{ padding: "16px 16px 20px" }}>

        {/* Greeting + nudges */}
        <div style={{ marginBottom: 14 }}>
          <div style={{ fontSize: 20, fontWeight: 800, color: C.text, marginBottom: 2 }}>
            {timeGreeting} {weather ? `· ${weather.temp}°` : ""}
          </div>
          <div style={{ fontSize: 11, color: C.sub }}>{now.toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric" })}</div>
        </div>
        {topNudges.map((n, i) => (
          <div key={i} style={{ background: "rgba(192,132,160,0.08)", border: `1px solid rgba(192,132,160,0.2)`, borderRadius: 12, padding: "11px 14px", marginBottom: 9 }}>
            <div style={{ fontSize: 12, color: "#e8c0d8", fontWeight: 600, lineHeight: 1.5 }}>{n.msg}</div>
          </div>
        ))}

        {/* Today's stats */}
        <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 16, padding: 16, marginBottom: 12 }}>
          <div style={{ fontSize: 9, fontWeight: 800, textTransform: "uppercase", letterSpacing: 1, color: C.sub, marginBottom: 12 }}>Today's snapshot</div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
            {[
              { label: "Workouts", val: `${workoutsDone}/5`, goal: null, color: C.dotPink, bg: "rgba(255,112,166,0.08)" },
              { label: "Calories", val: foodTotals.calories, goal: CALORIE_GOAL, unit: "", color: C.amber, bg: "rgba(232,130,154,0.08)" },
              { label: "Water", val: waterOz, goal: WATER_GOAL_OZ, unit: "oz", color: C.dotBlue, bg: "rgba(107,230,247,0.08)" },
              { label: "Protein", val: foodTotals.protein, goal: PROTEIN_GOAL, unit: "g", color: C.sage, bg: "rgba(123,191,160,0.08)" },
            ].map(({ label, val, goal, unit, color, bg }) => (
              <div key={label} style={{ background: bg, borderRadius: 12, padding: "12px 13px" }}>
                <div style={{ fontSize: 9, color: C.sub, fontWeight: 700, textTransform: "uppercase", letterSpacing: .5, marginBottom: 6 }}>{label}</div>
                <div style={{ fontSize: 22, fontWeight: 800, color, lineHeight: 1 }}>{val}<span style={{ fontSize: 11, color: C.sub, fontWeight: 500 }}>{unit}</span></div>
                {goal && <div style={{ fontSize: 9, color: C.sub, marginTop: 4 }}>of {goal}{unit}</div>}
              </div>
            ))}
          </div>
        </div>

        {/* Weight progress */}
        <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 16, padding: 16, marginBottom: 12, display: "flex", gap: 14, alignItems: "center" }}>
          <svg width="64" height="64" viewBox="0 0 64 64" style={{ flexShrink: 0 }}>
            <circle cx="32" cy="32" r="26" fill="none" stroke={C.border} strokeWidth="6"/>
            <circle cx="32" cy="32" r="26" fill="none" stroke={C.rose} strokeWidth="6"
              strokeDasharray="163.4" strokeDashoffset={163.4 * (1 - pct/100)} strokeLinecap="round"
              transform="rotate(-90 32 32)"/>
            <text x="32" y="29" textAnchor="middle" fontSize="11" fontWeight="800" fill="#f0e8f5">{pct}%</text>
            <text x="32" y="40" textAnchor="middle" fontSize="7" fill={C.sub}>there</text>
          </svg>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 14, fontWeight: 800, color: C.text, marginBottom: 3 }}>{latest} → {GOAL_WEIGHT} lbs 💜</div>
            <div style={{ fontSize: 11, color: C.sub, lineHeight: 1.75 }}>
              {remaining > 0 ? `${remaining} lbs to go` : "Goal reached! 🎉"}<br/>
              {td && <span style={{ color: C.amber, fontWeight: 700 }}>Est. {fmtDate(td)}</span>}
              {td && <span style={{ color: C.sub }}> · {weeksAway(td)}</span>}
            </div>
          </div>
        </div>

        {/* Quick log */}
        <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 16, padding: 16 }}>
          <div style={{ fontSize: 9, fontWeight: 800, textTransform: "uppercase", letterSpacing: 1, color: C.sub, marginBottom: 12 }}>Quick log</div>
          <div style={{ display: "flex", gap: 8 }}>
            {[
              { emoji: "⚖️", label: "Weight", color: C.rose, bg: "rgba(192,132,160,0.12)", tab: "weight" },
              { emoji: "🥗", label: "Food", color: C.sage, bg: "rgba(123,191,160,0.12)", tab: "nutrition" },
              { emoji: "💧", label: "Water", color: C.dotBlue, bg: "rgba(107,230,247,0.12)", tab: "habits" },
              { emoji: "😴", label: "Sleep", color: C.plum, bg: "rgba(160,124,192,0.12)", tab: "habits" },
            ].map(q => (
              <button key={q.label} onClick={() => setActiveTab(q.tab)} style={{ flex: 1, padding: "12px 4px", borderRadius: 12, fontSize: 11, fontWeight: 700, cursor: "pointer", border: "none", display: "flex", flexDirection: "column", alignItems: "center", gap: 5, background: q.bg, color: q.color, fontFamily: "inherit" }}>
                <span style={{ fontSize: 19 }}>{q.emoji}</span>
                <span>{q.label}</span>
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

function StreakTab({ weeklyHistory, weightLog, splurgeRewards, setSplurgeRewards }) {
  const today = new Date();
  let streak = 0;
  for (let i = 0; i < 365; i++) {
    const d = new Date(today); d.setDate(d.getDate() - i);
    const k = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
    const h = weeklyHistory[k];
    if (h?.workout || h?.yoga) streak++;
    else if (i > 0) break;
  }
  // Individual category streaks
  const calcCategoryStreak = (field) => {
    let s = 0;
    for (let i = 0; i < 365; i++) {
      const d = new Date(today); d.setDate(d.getDate() - i);
      const k = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
      const h = weeklyHistory[k];
      if (h?.[field]) s++; else if (i > 0) break;
    }
    return s;
  };
  const workoutStreak = calcCategoryStreak("workout");
  const yogaStreak = calcCategoryStreak("yoga");
  const thatGirlStreak = calcCategoryStreak("thatGirl");
  // No fast food streak — a day counts if noJunk flag is explicitly set true
  const noFastFoodStreak = calcCategoryStreak("noJunk");

  let bestStreak = 0, cur = 0;
  const allDays = Object.keys(weeklyHistory).sort();
  for (const k of allDays) {
    const h = weeklyHistory[k];
    if (h?.workout || h?.yoga) { cur++; if (cur > bestStreak) bestStreak = cur; } else cur = 0;
  }
  const totalWorkouts = Object.values(weeklyHistory).filter(h => h?.workout).length;
  const purpleDays = Object.values(weeklyHistory).filter(h => h?.workout && h?.yoga && h?.nutrition).length;
  const latest = weightLog.length > 0 ? parseFloat(weightLog[0].weight) : START_WEIGHT;
  const td = calcTargetDate(latest);
  const BADGES = [
    { id: "7d", emoji: "🌸", label: "7-day streak", desc: "7 consistent days", req: streak >= 7, todo: Math.max(0, 7 - streak) },
    { id: "21d", emoji: "💜", label: "21-day streak", desc: "21 consistent days", req: streak >= 21, todo: Math.max(0, 21 - streak) },
    { id: "30d", emoji: "🔥", label: "30-day streak", desc: "30 consecutive days", req: streak >= 30, todo: Math.max(0, 30 - streak) },
    { id: "60d", emoji: "⚡", label: "60-day streak", desc: "60 consecutive days", req: streak >= 60, todo: Math.max(0, 60 - streak) },
    { id: "90d", emoji: "👑", label: "90-day streak", desc: "90 consecutive days", req: streak >= 90, todo: Math.max(0, 90 - streak) },
    { id: "100w", emoji: "💯", label: "100 workouts", desc: "Complete 100 workouts", req: totalWorkouts >= 100, todo: Math.max(0, 100 - totalWorkouts) },
    { id: "7pg", emoji: "✨", label: "7 That Girl Days", desc: "Hit ALL goals 7 days", req: purpleDays >= 7, todo: Math.max(0, 7 - purpleDays), wide: true },
  ];
  const SPLURGE = [
    { id: "7", emoji: "🌸", label: "7-day reward", earned: streak >= 7 },
    { id: "30", emoji: "🔥", label: "30-day reward", earned: streak >= 30 },
    { id: "90", emoji: "👑", label: "90-day reward", earned: streak >= 90 },
  ];
  const year = today.getFullYear(); const month = today.getMonth();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const firstDay = new Date(year, month, 1).getDay();
  const monthStart = (firstDay + 6) % 7;
  const monthNames = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
  const todayKey = getTodayKey();
  return (
    <div style={{ padding: "16px 14px 24px" }}>
      <Card style={{ display: "flex", gap: 14, alignItems: "center" }}>
        <div style={{ width: 58, height: 58, borderRadius: "50%", border: `2px solid ${C.rose}`, background: "rgba(192,132,160,0.1)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
          <div style={{ fontSize: 22, fontWeight: 800, color: "#e8c0d8" }}>{streak}</div>
          <div style={{ fontSize: 8, color: C.sub, fontWeight: 700, letterSpacing: .5 }}>DAYS</div>
        </div>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 14, fontWeight: 700, color: C.text, marginBottom: 2 }}>Current streak</div>
          <div style={{ fontSize: 11, color: C.sub, marginBottom: 8 }}>Best: {bestStreak} days · {totalWorkouts} total workouts</div>
          {td && <div style={{ paddingTop: 8, borderTop: `1px solid ${C.border}` }}>
            <div style={{ fontSize: 10, color: C.sub }}>Estimated goal date</div>
            <div style={{ fontSize: 13, fontWeight: 700, color: C.amber, marginTop: 2 }}>{fmtDate(td)} <span style={{ fontSize: 10, fontWeight: 400, color: C.sub }}>· {weeksAway(td)}</span></div>
          </div>}
        </div>
      </Card>

      {/* Per-category streak bubbles */}
      <div style={{ display: "flex", gap: 8, marginBottom: 12 }}>
        {[
          { val: workoutStreak, label: "💪 Workout", color: C.dotPink },
          { val: yogaStreak, label: "🧘 Yoga", color: C.dotGreen },
          { val: noFastFoodStreak, label: "🍔 No fast food", color: C.amber },
          { val: thatGirlStreak, label: "✨ That Girl", color: C.dotPurple },
        ].map(b => (
          <div key={b.label} style={{ flex: 1, background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12, padding: "10px 6px", textAlign: "center" }}>
            <div style={{ fontSize: 16, fontWeight: 800, color: b.color }}>{b.val}</div>
            <div style={{ fontSize: 8, color: C.sub, marginTop: 2, fontWeight: 700 }}>{b.label}</div>
          </div>
        ))}
      </div>

      <Card>
        <SectionLabel>{monthNames[month]} {year}</SectionLabel>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 3, textAlign: "center", marginBottom: 5 }}>
          {["M","T","W","T","F","S","S"].map((d,i) => <div key={i} style={{ fontSize: 9, color: C.muted }}>{d}</div>)}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", gap: 3, textAlign: "center" }}>
          {Array.from({ length: monthStart }).map((_, i) => <div key={`e${i}`} />)}
          {Array.from({ length: daysInMonth }).map((_, i) => {
            const day = i + 1;
            const d = new Date(year, month, day);
            const k = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
            const h = weeklyHistory[k] || {};
            const isToday = k === todayKey;
            const isFuture = d > today;
            const hasDots = h.workout || h.yoga || h.nutrition;
            const numColor = h.workout ? C.dotPink : h.yoga ? C.dotGreen : hasDots ? C.sub : isFuture ? "#3a2a4a" : C.muted;
            return (
              <div key={day} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 3, padding: "3px 0", borderRadius: 6, border: isToday ? `1.5px solid ${C.dotPink}` : "1.5px solid transparent", opacity: isFuture ? 0.2 : 1 }}>
                <div style={{ fontSize: 10, color: numColor, fontWeight: hasDots ? 700 : 400 }}>{day}</div>
                <div style={{ display: "flex", gap: 2, justifyContent: "center", minHeight: 7 }}>
                  {h.workout && <div style={{ width: 5, height: 5, borderRadius: "50%", background: C.dotPink }} />}
                  {h.yoga && <div style={{ width: 5, height: 5, borderRadius: "50%", background: C.dotGreen }} />}
                  {h.nutrition && <div style={{ width: 5, height: 5, borderRadius: "50%", background: C.dotBlue }} />}
                  {h.workout && h.yoga && h.nutrition && <div style={{ width: 5, height: 5, borderRadius: "50%", background: C.dotPurple, boxShadow: `0 0 4px ${C.dotPurple}` }} />}
                </div>
              </div>
            );
          })}
        </div>
        <div style={{ marginTop: 12, paddingTop: 10, borderTop: `1px solid ${C.border}`, display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6 }}>
          {[
            { color: C.dotPink, label: "Workout" },
            { color: C.dotGreen, label: "Yoga / recovery" },
            { color: C.dotBlue, label: "Nutrition on track" },
            { color: C.dotPurple, label: "✨ That Girl Day" },
          ].map(({ color, label }) => (
            <div key={label} style={{ display: "flex", alignItems: "center", gap: 5 }}>
              <div style={{ width: 7, height: 7, borderRadius: "50%", background: color }} />
              <span style={{ fontSize: 9, color: C.sub }}>{label}</span>
            </div>
          ))}
        </div>
      </Card>
      <Card>
        <SectionLabel>Streak badges</SectionLabel>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
          {BADGES.map(b => (
            <div key={b.id} style={{ gridColumn: b.wide ? "span 2" : "span 1", background: b.req ? "rgba(192,132,160,0.1)" : C.surface, border: `1px solid ${b.req ? "rgba(192,132,160,0.3)" : C.border}`, borderRadius: 10, padding: 10, textAlign: "center", opacity: b.req ? 1 : 0.42 }}>
              <div style={{ fontSize: 24, marginBottom: 4 }}>{b.emoji}</div>
              <div style={{ fontSize: 11, fontWeight: 700, color: b.req ? "#e8c0d8" : C.sub }}>{b.label}</div>
              <div style={{ fontSize: 9, color: C.sub, marginTop: 2 }}>{b.desc}</div>
              <div style={{ fontSize: 8, fontWeight: 700, color: b.req ? C.rose : C.muted, marginTop: 4, background: b.req ? "rgba(192,132,160,0.15)" : C.inputBg, borderRadius: 4, padding: "2px 6px", display: "inline-block" }}>
                {b.req ? "✓ UNLOCKED" : `${b.todo} to go`}
              </div>
            </div>
          ))}
        </div>
      </Card>
      <Card>
        <SectionLabel>Splurge rewards 🛍️</SectionLabel>
        <div style={{ fontSize: 10, color: C.sub, marginBottom: 10, lineHeight: 1.6 }}>Set a treat for hitting each milestone.</div>
        <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
          {SPLURGE.map(m => (
            <div key={m.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "9px 10px", background: m.earned ? "rgba(192,132,160,0.08)" : C.surface, border: `1px ${m.earned ? "solid rgba(192,132,160,0.2)" : "dashed ${C.border}"}`, borderRadius: 9 }}>
              <div style={{ fontSize: 16 }}>{m.emoji}</div>
              <div style={{ flex: 1 }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: m.earned ? "#e8c0d8" : C.sub }}>{m.label}</div>
                <input value={splurgeRewards[m.id] || ""} onChange={e => setSplurgeRewards(p => ({ ...p, [m.id]: e.target.value }))} placeholder="Tap to set your splurge…" style={{ fontSize: 10, color: splurgeRewards[m.id] ? C.text : C.muted, background: "transparent", border: "none", outline: "none", width: "100%", fontStyle: splurgeRewards[m.id] ? "normal" : "italic", fontFamily: "inherit", marginTop: 2 }} />
              </div>
              {m.earned && <div style={{ fontSize: 8, fontWeight: 700, color: C.rose, background: "rgba(192,132,160,0.15)", borderRadius: 4, padding: "2px 7px" }}>EARNED</div>}
            </div>
          ))}
        </div>
      </Card>
    </div>
  );
}

// ── EMOJI CATEGORIES for habit picker
const EMOJI_CATS = [
  { label: "💆 Self care", emojis: ["🧴","💅","🛁","🪞","💊","🧘","🌿","🫧"] },
  { label: "🌙 Sleep / rest", emojis: ["🌙","😴","📵","🕯️","🛌","🌛","💤"] },
  { label: "🏃 Movement", emojis: ["🚶","🧗","🤸","🏊","🚴","🚿","🏋️","🪃"] },
  { label: "📚 Mind", emojis: ["📓","📖","🧠","🎨","🎵","✍️","🎯","🧩"] },
  { label: "🌸 Wellness", emojis: ["💧","🍵","🥗","🌸","☀️","🌷","🫶","✨"] },
];
const HABIT_COLORS = [
  "rgba(192,132,160,0.18)","rgba(160,124,192,0.18)","rgba(107,230,247,0.18)",
  "rgba(169,191,83,0.18)","rgba(255,112,166,0.18)","rgba(123,191,160,0.18)",
  "rgba(232,130,154,0.18)","rgba(223,132,189,0.18)",
];
const SUPP_ROUTINE = [
  { week: 1, time: "am", name: "D3 + K2 5,000 IU", note: "Nature Made · with fat", freq: "Every other day" },
  { week: 1, time: "am", name: "Omega-3 500mg", note: "NatureWise", freq: "Daily" },
  { week: 2, time: "pm", name: "Magnesium Glycinate 200mg", note: "Nature Made", freq: "Daily" },
  { week: 3, time: "mid", name: "Vitamin C 500mg", note: "Nature Made Rose Hips", freq: "Daily" },
  { week: 4, time: "pm", name: "Zinc 30mg", note: "Nutricost · 5 days/week", freq: "5 days/week" },
  { week: 4, time: "am", name: "Collagen peptides", note: "Nutricost · in smoothie", freq: "Daily" },
  { week: 5, time: "pm", name: "B Complex", note: "NatureWise · weekdays only", freq: "Weekdays" },
];

function HabitsTab({ waterTaps, setWaterTaps, dailyStats, setDailyStats, habits, setHabits, habitsDone, setHabitsDone, cycleLog, setCycleLog, suppRoutineWeek, setSuppRoutineWeek, suppRoutineComplete, setSuppRoutineComplete, customSupps, setCustomSupps, customSuppsDone, setCustomSuppsDone }) {
  const [pill, setPill] = useState("trackers");
  const todayKey = getTodayKey();
  const waterOz = waterTaps * 8;

  // Supplement streak
  const calcSuppStreak = () => {
    let s = 0;
    const today = new Date();
    for (let i = 0; i < 90; i++) {
      const d = new Date(today); d.setDate(d.getDate() - i);
      const k = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
      const done = loadS(`custom-supps-done-${k}`, {});
      const checked = Object.values(done).filter(Boolean).length;
      if (checked > 0) s++; else if (i > 0) break;
    }
    return s;
  };
  const suppStreak = calcSuppStreak();

  // Habit streak (overall — any habit done)
  const calcHabitStreak = () => {
    let s = 0;
    const today = new Date();
    for (let i = 0; i < 90; i++) {
      const d = new Date(today); d.setDate(d.getDate() - i);
      const k = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
      const done = loadS(`habits-done-${k}`, {});
      if (Object.values(done).some(Boolean)) s++; else if (i > 0) break;
    }
    return s;
  };
  const habitStreak = calcHabitStreak();

  // Add habit form state
  const [showAddHabit, setShowAddHabit] = useState(false);
  const [newHabitName, setNewHabitName] = useState("");
  const [newHabitEmoji, setNewHabitEmoji] = useState("✨");
  const [newHabitColor, setNewHabitColor] = useState(HABIT_COLORS[0]);
  const [editSheet, setEditSheet] = useState(null); // habit id
  const [editField, setEditField] = useState(null); // "name"|"emoji"|"color"

  // Add supplement form state
  const [showAddSupp, setShowAddSupp] = useState(false);
  const [newSuppName, setNewSuppName] = useState("");
  const [newSuppNote, setNewSuppNote] = useState("");
  const [newSuppTime, setNewSuppTime] = useState("am");
  const [suppEditSheet, setSuppEditSheet] = useState(null);

  // Cycle state
  const today = getTodayKey();
  const todayCycle = cycleLog[today] || { flow: "", mucus: "", feelings: [], cravings: [], symptoms: [] };
  const updateCycleToday = (patch) => {
    const updated = { ...cycleLog, [today]: { ...todayCycle, ...patch } };
    setCycleLog(updated);
    saveS("cycle-log", updated);
  };
  const [cycleCategory, setCycleCategory] = useState("flow");
  const [showPeriodDialog, setShowPeriodDialog] = useState(false);

  // Find last period start/end to calculate day + phase
  const periodStarts = Object.entries(cycleLog).filter(([, v]) => v.periodEvent === "start").map(([k]) => k).sort();
  const periodEnds = Object.entries(cycleLog).filter(([, v]) => v.periodEvent === "end").map(([k]) => k).sort();
  const lastPeriodStart = periodStarts[periodStarts.length - 1];
  const lastPeriodEnd = periodEnds[periodEnds.length - 1];
  const isOnPeriod = lastPeriodStart && (!lastPeriodEnd || lastPeriodEnd < lastPeriodStart);
  const dayOfCycle = lastPeriodStart ? Math.floor((new Date(today) - new Date(lastPeriodStart)) / 86400000) + 1 : null;
  const AVG_CYCLE = 28;
  const daysLeft = lastPeriodStart ? AVG_CYCLE - dayOfCycle : null;
  const phase = isOnPeriod ? "period" : dayOfCycle ? (dayOfCycle <= 5 ? "period" : dayOfCycle <= 13 ? "follicular" : dayOfCycle <= 15 ? "ovulation" : "luteal") : null;
  const nextPeriod = lastPeriodStart ? new Date(new Date(lastPeriodStart).getTime() + AVG_CYCLE * 86400000) : null;

  const PHASE_INFO = {
    period: { emoji: "🩸", label: "Period Phase", color: C.dotPink },
    follicular: { emoji: "🌱", label: "Follicular Phase", color: C.sage },
    ovulation: { emoji: "🌸", label: "Ovulation Phase", color: C.rose },
    luteal: { emoji: "🌙", label: "Luteal Phase", color: C.plum },
  };
  const AFFIRMATIONS = {
    period: ["Rest is productive. Let your body recover today.", "Softness is strength — honor what you need right now.", "You don't have to push today. Slowing down is enough."],
    follicular: ["Fresh energy is building — a great day to start something new.", "Your creativity is peaking. Follow the spark.", "Momentum is on your side today — use it."],
    ovulation: ["Your energy is magnetic today — trust your confidence and let yourself shine.", "You're at your most social, capable self right now.", "This is your power phase — go after what you want."],
    luteal: ["Patience with yourself is the assignment today.", "Slow down, tune in, and give yourself grace.", "Your intuition is heightened — listen to it."],
  };
  const todayAffirmation = phase ? AFFIRMATIONS[phase][new Date().getDate() % AFFIRMATIONS[phase].length] : "Log your period to unlock daily affirmations tailored to your cycle.";

  const CYCLE_CATEGORIES = [
    { id: "flow", emoji: "🩸", label: "Flow", options: [
      { emoji: "💧", label: "Light" }, { emoji: "🩸", label: "Medium" }, { emoji: "🔴", label: "Heavy" }, { emoji: "⚪", label: "None" },
    ]},
    { id: "mucus", emoji: "💧", label: "Mucus", options: [
      { emoji: "💦", label: "Watery" }, { emoji: "🥚", label: "Egg white" }, { emoji: "🤍", label: "Creamy" }, { emoji: "🍯", label: "Sticky" },
    ]},
    { id: "feelings", emoji: "😊", label: "Feelings", multi: true, options: [
      { emoji: "⚡", label: "Energized" }, { emoji: "😴", label: "Exhausted" }, { emoji: "😰", label: "Anxious" }, { emoji: "😌", label: "Calm" },
    ]},
    { id: "cravings", emoji: "🍫", label: "Cravings", multi: true, options: [
      { emoji: "🧂", label: "Salty" }, { emoji: "🍰", label: "Sweet" }, { emoji: "🍫", label: "Chocolate" }, { emoji: "🍞", label: "Carbs" },
    ]},
    { id: "symptoms", emoji: "🩹", label: "Symptoms", multi: true, options: [
      { emoji: "😣", label: "Cramps" }, { emoji: "🤕", label: "Headache" }, { emoji: "🫄", label: "Bloating" }, { emoji: "💆", label: "Tender" },
    ]},
  ];
  const activeCategory = CYCLE_CATEGORIES.find(c => c.id === cycleCategory);
  const toggleCycleOption = (catId, label, multi) => {
    if (multi) {
      const curr = todayCycle[catId] || [];
      const updated = curr.includes(label) ? curr.filter(x => x !== label) : [...curr, label];
      updateCycleToday({ [catId]: updated });
    } else {
      updateCycleToday({ [catId]: todayCycle[catId] === label ? "" : label });
    }
  };

  const PillBtn = ({ id, label }) => (
    <button onClick={() => setPill(id)} style={{ flexShrink: 0, padding: "7px 14px", borderRadius: 20, fontSize: 11, fontWeight: 700, border: pill === id ? "none" : "1.5px solid C.border", background: pill === id ? C.rose : C.surface, color: pill === id ? "#fff" : C.sub, cursor: "pointer", whiteSpace: "nowrap", fontFamily: "inherit" }}>{label}</button>
  );

  return (
    <div>
      {/* Pill tabs */}
      <div style={{ display: "flex", gap: 7, overflowX: "auto", padding: "14px 14px 10px" }}>
        <PillBtn id="trackers" label="📊 Trackers" />
        <PillBtn id="personal" label="✨ Personal" />
        <PillBtn id="supplements" label="💊 Supplements" />
        <PillBtn id="cycle" label="🌸 Cycle" />
      </div>

      {/* ── TRACKERS ── */}
      {pill === "trackers" && (
        <div style={{ padding: "4px 14px 24px" }}>
          {/* Water */}
          <Card>
            <SectionLabel>💧 Water — {waterOz} / {WATER_GOAL_OZ} oz</SectionLabel>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 8 }}>
              {Array.from({ length: 10 }).map((_, i) => {
                const filled = i < waterTaps;
                return (
                  <button key={i} onClick={() => setWaterTaps(filled ? i : i + 1)} style={{ background: "transparent", border: "none", cursor: "pointer", padding: 2, lineHeight: 1 }}>
                    <svg width="26" height="34" viewBox="0 0 28 36">
                      <path d="M14 2 C14 2 2 14 2 24 a12 12 0 0 0 24 0 C26 14 14 2 14 2z" fill={filled ? C.dotBlue : "none"} stroke={filled ? C.dotBlue : "rgba(107,230,247,0.35)"} strokeWidth="1.5" opacity={filled ? 0.9 : 0.5} />
                    </svg>
                  </button>
                );
              })}
            </div>
            <div style={{ fontSize: 9, color: C.sub }}>Each drop = 8 oz · tap to fill / unfill</div>
          </Card>

          {/* Steps */}
          <Card>
            <SectionLabel>👟 Steps</SectionLabel>
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 5, minWidth: 0 }}>
              <input type="number" value={dailyStats.steps || ""} onChange={e => setDailyStats(p => ({ ...p, steps: Number(e.target.value) || 0 }))} placeholder="0" style={{ flex: 1, minWidth: 0, background: C.inputBg, border: `1px solid ${C.border}`, borderRadius: 8, padding: "8px 10px", color: C.text, fontSize: 15, fontWeight: 700, fontFamily: "inherit", outline: "none", boxSizing: "border-box" }} />
              <span style={{ fontSize: 12, fontWeight: 700, color: C.dotGreen, flexShrink: 0, whiteSpace: "nowrap" }}>{Math.min(100, Math.round((dailyStats.steps / STEPS_GOAL) * 100))}%</span>
            </div>
            <div style={{ height: 5, borderRadius: 3, background: C.border, overflow: "hidden" }}>
              <div style={{ height: "100%", width: `${Math.min(100, Math.round((dailyStats.steps / STEPS_GOAL) * 100))}%`, background: C.dotGreen, borderRadius: 3 }} />
            </div>
            <div style={{ fontSize: 9, color: C.sub, marginTop: 3 }}>Goal: {STEPS_GOAL.toLocaleString()} steps</div>
          </Card>

          {/* Sleep */}
          <Card>
            <SectionLabel>😴 Sleep</SectionLabel>
            <div style={{ fontSize: 24, fontWeight: 800, color: C.plum, textAlign: "center", margin: "4px 0 2px" }}>{dailyStats.sleep || 0} hrs</div>
            <div style={{ fontSize: 9, color: C.sub, textAlign: "center", marginBottom: 8 }}>Goal: {SLEEP_GOAL_HRS} hrs</div>
            <input type="range" min="0" max="12" step="0.5" value={dailyStats.sleep || 0} onChange={e => setDailyStats(p => ({ ...p, sleep: parseFloat(e.target.value) }))} style={{ width: "100%", accentColor: C.plum }} />
            <div style={{ height: 5, borderRadius: 3, background: C.border, overflow: "hidden", marginTop: 4 }}>
              <div style={{ height: "100%", width: `${Math.min(100, Math.round(((dailyStats.sleep || 0) / SLEEP_GOAL_HRS) * 100))}%`, background: C.plum, borderRadius: 3 }} />
            </div>
          </Card>
        </div>
      )}

      {/* ── PERSONAL HABITS ── */}
      {pill === "personal" && (
        <div style={{ padding: "4px 14px 24px" }}>
          {showAddHabit ? (
            <Card>
              <div style={{ fontSize: 14, fontWeight: 800, color: C.text, marginBottom: 14 }}>
                {editField ? "Edit habit" : "New habit ✨"}
              </div>
              <div style={{ fontSize: 9, fontWeight: 800, textTransform: "uppercase", letterSpacing: 1, color: C.sub, marginBottom: 6 }}>Habit name</div>
              <input value={newHabitName} onChange={e => setNewHabitName(e.target.value)} placeholder="e.g. Morning walk…" style={{ width: "100%", background: C.inputBg, border: `1px solid ${C.border}`, borderRadius: 9, padding: "9px 12px", color: C.text, fontSize: 13, fontFamily: "inherit", outline: "none", marginBottom: 14, boxSizing: "border-box" }} />

              <div style={{ fontSize: 9, fontWeight: 800, textTransform: "uppercase", letterSpacing: 1, color: C.sub, marginBottom: 8 }}>Pick an emoji</div>
              {EMOJI_CATS.map(cat => (
                <div key={cat.label} style={{ marginBottom: 10 }}>
                  <div style={{ fontSize: 9, color: C.muted, fontWeight: 700, marginBottom: 5 }}>{cat.label}</div>
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 5 }}>
                    {cat.emojis.map(e => (
                      <button key={e} onClick={() => setNewHabitEmoji(e)} style={{ width: 32, height: 32, borderRadius: 8, fontSize: 16, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer", border: newHabitEmoji === e ? `1.5px solid ${C.plum}` : "1.5px solid transparent", background: newHabitEmoji === e ? "rgba(160,124,192,0.18)" : C.surface, fontFamily: "inherit" }}>{e}</button>
                    ))}
                  </div>
                </div>
              ))}

              <div style={{ fontSize: 9, fontWeight: 800, textTransform: "uppercase", letterSpacing: 1, color: C.sub, margin: "10px 0 8px" }}>Icon color</div>
              <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 14 }}>
                {HABIT_COLORS.map(col => (
                  <button key={col} onClick={() => setNewHabitColor(col)} style={{ width: 28, height: 28, borderRadius: "50%", background: col, border: newHabitColor === col ? "2px solid #fff" : "2px solid transparent", cursor: "pointer", transform: newHabitColor === col ? "scale(1.15)" : "scale(1)", transition: "all 0.15s" }} />
                ))}
              </div>

              {/* Preview */}
              <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "11px 13px", background: C.surface, borderRadius: 10, marginBottom: 14, border: `1px solid ${C.border}` }}>
                <div style={{ width: 34, height: 34, borderRadius: 10, background: newHabitColor, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 17, flexShrink: 0 }}>{newHabitEmoji}</div>
                <div>
                  <div style={{ fontSize: 13, fontWeight: 600, color: C.text }}>{newHabitName || "Your habit name"}</div>
                  <div style={{ fontSize: 9, color: C.sub, marginTop: 2 }}>Preview</div>
                </div>
              </div>

              <button onClick={() => {
                if (!newHabitName.trim()) return;
                const newH = { id: `h${Date.now()}`, name: newHabitName.trim(), emoji: newHabitEmoji, color: newHabitColor, streak: 0, lastDone: "" };
                setHabits(p => [...p, newH]);
                setNewHabitName(""); setNewHabitEmoji("✨"); setNewHabitColor(HABIT_COLORS[0]);
                setShowAddHabit(false);
              }} style={{ width: "100%", padding: 10, borderRadius: 10, border: "none", background: C.plum, color: "#fff", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit", marginBottom: 7 }}>Save habit</button>
              <button onClick={() => setShowAddHabit(false)} style={{ width: "100%", padding: 8, borderRadius: 10, border: `1px solid ${C.border}`, background: "transparent", color: C.muted, fontSize: 12, cursor: "pointer", fontFamily: "inherit" }}>Cancel</button>
            </Card>
          ) : (
            <Card>
              {habits.length === 0 && (
                <div style={{ textAlign: "center", padding: "20px 0", color: C.muted, fontSize: 12 }}>No habits yet — add your first one below!</div>
              )}
              {habits.map(h => (
                <div key={h.id} style={{ display: "flex", alignItems: "center", gap: 9, marginBottom: 10 }}>
                  <div style={{ width: 30, height: 30, borderRadius: 9, background: h.color, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 15, flexShrink: 0 }}>{h.emoji}</div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 12, fontWeight: 600, color: habitsDone[h.id] ? C.sub : C.text, textDecoration: habitsDone[h.id] ? "line-through" : "none" }}>{h.name}</div>
                    <div style={{ fontSize: 9, color: C.sub, marginTop: 1 }}>🔥 {h.streak} day streak</div>
                  </div>
                  <button className="check-anim" onClick={() => {
                    const newDone = !habitsDone[h.id];
                    setHabitsDone(p => ({ ...p, [h.id]: newDone }));
                    if (newDone) {
                      setHabits(prev => prev.map(x => x.id === h.id ? { ...x, streak: (x.streak || 0) + 1, lastDone: todayKey } : x));
                    }
                  }} style={{ width: 22, height: 22, borderRadius: 6, border: `1.5px solid ${habitsDone[h.id] ? C.dotGreen : C.border}`, background: habitsDone[h.id] ? "rgba(169,191,83,0.2)" : "transparent", color: C.dotGreen, fontSize: 12, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, transition: "transform 0.15s, background 0.15s" }}>{habitsDone[h.id] ? "✓" : ""}</button>
                  <button onClick={() => setEditSheet(h.id)} style={{ fontSize: 14, color: C.muted, background: "none", border: "none", cursor: "pointer", padding: "0 2px", flexShrink: 0 }}>···</button>
                </div>
              ))}
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginTop: 10, padding: "8px 10px", background: "rgba(192,132,160,0.08)", borderRadius: 8 }}>
                <div style={{ fontSize: 10, color: C.sub }}>✨ Habit streak</div>
                <div style={{ fontSize: 14, fontWeight: 800, color: C.dotPurple }}>🔥 {habitStreak} days</div>
              </div>
              <button onClick={() => setShowAddHabit(true)} style={{ width: "100%", marginTop: 10, padding: 9, borderRadius: 9, border: "1px dashed C.border", background: "transparent", color: C.muted, fontSize: 11, cursor: "pointer", fontFamily: "inherit" }}>+ Add a habit</button>
            </Card>
          )}

          {/* Edit sheet */}
          {editSheet && (() => {
            const h = habits.find(x => x.id === editSheet);
            if (!h) return null;
            return (
              <div style={{ position: "fixed", inset: 0, zIndex: 50, display: "flex", flexDirection: "column", justifyContent: "flex-end" }} onClick={() => setEditSheet(null)}>
                <div style={{ background: "#1e1228", borderRadius: "16px 16px 0 0", padding: "16px 14px 32px", border: `1px solid ${C.border}` }} onClick={e => e.stopPropagation()}>
                  <div style={{ width: 36, height: 4, background: C.border, borderRadius: 2, margin: "0 auto 14px" }} />
                  <div style={{ fontSize: 13, fontWeight: 800, color: C.text, marginBottom: 4 }}>{h.emoji} {h.name}</div>
                  <div style={{ fontSize: 9, color: C.sub, marginBottom: 16 }}>🔥 {h.streak} day streak</div>
                  {[
                    { icon: "✏️", label: "Edit name", action: () => { setNewHabitName(h.name); setNewHabitEmoji(h.emoji); setNewHabitColor(h.color); setShowAddHabit(true); setEditSheet(null); } },
                    { icon: "😊", label: "Change emoji", action: () => { setNewHabitName(h.name); setNewHabitEmoji(h.emoji); setNewHabitColor(h.color); setShowAddHabit(true); setEditSheet(null); } },
                    { icon: "🎨", label: "Change color", action: () => { setNewHabitName(h.name); setNewHabitEmoji(h.emoji); setNewHabitColor(h.color); setShowAddHabit(true); setEditSheet(null); } },
                    { icon: "🔥", label: "Reset streak", action: () => { setHabits(p => p.map(x => x.id === h.id ? { ...x, streak: 0 } : x)); setEditSheet(null); } },
                    { icon: "🗑️", label: "Delete habit", danger: true, action: () => { setHabits(p => p.filter(x => x.id !== h.id)); setEditSheet(null); } },
                  ].map((opt, i) => (
                    <button key={i} onClick={opt.action} style={{ width: "100%", display: "flex", alignItems: "center", gap: 12, padding: "11px 4px", background: "none", border: "none", borderBottom: i < 4 ? `1px solid ${C.border}` : "none", cursor: "pointer", color: opt.danger ? C.amber : C.text, fontFamily: "inherit", fontSize: 13 }}>
                      <span style={{ fontSize: 16, width: 24, textAlign: "center" }}>{opt.icon}</span>
                      {opt.label}
                    </button>
                  ))}
                </div>
              </div>
            );
          })()}
        </div>
      )}

      {/* ── SUPPLEMENTS ── */}
      {pill === "supplements" && (
        <div style={{ padding: "4px 14px 24px" }}>
          {suppRoutineComplete ? (
            <>
              {/* Achieved banner */}
              <div style={{ background: "linear-gradient(135deg, rgba(169,191,83,0.1), rgba(123,191,160,0.1))", border: "1px solid rgba(169,191,83,0.25)", borderRadius: 12, padding: "12px 14px", marginBottom: 12 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}>
                  <span style={{ fontSize: 28 }}>🎉</span>
                  <div>
                    <div style={{ fontSize: 13, fontWeight: 800, color: C.dotGreen }}>Routine complete!</div>
                    <div style={{ fontSize: 10, color: C.sub, marginTop: 2, lineHeight: 1.4 }}>You built your full stack. Now it's yours to customize.</div>
                  </div>
                </div>
                <button onClick={() => {
                  setSuppRoutineComplete(false);
                  setSuppRoutineWeek(1);
                  setCustomSupps([]);
                  saveS("supp-routine-complete", false);
                  saveS("supp-routine-week", 1);
                  saveS("custom-supps", []);
                }} style={{ width: "100%", padding: "7px", borderRadius: 8, border: "1px solid rgba(232,130,154,0.3)", background: "rgba(232,130,154,0.08)", color: C.amber, fontSize: 11, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>
                  ↩ Restart routine from Week 1
                </button>
              </div>

              {/* Custom supplement list — main focus */}
              <Card>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
                  <div style={{ fontSize: 12, fontWeight: 800, color: C.text }}>My supplements</div>
                  <div style={{ fontSize: 9, color: C.dotGreen, background: "rgba(169,191,83,0.1)", padding: "3px 9px", borderRadius: 20, fontWeight: 700 }}>
                    {Object.values(customSuppsDone).filter(Boolean).length}/{customSupps.length} done
                  </div>
                </div>

                {["am","mid","pm"].map(time => {
                  const timeSups = customSupps.filter(s => s.time === time);
                  if (timeSups.length === 0) return null;
                  const timeLabel = time === "am" ? "☀️ Morning" : time === "mid" ? "🌤️ Afternoon" : "🌙 Evening";
                  const timeColor = time === "am" ? C.dotPink : time === "mid" ? C.dotBlue : C.plum;
                  return (
                    <div key={time}>
                      <div style={{ fontSize: 9, fontWeight: 800, textTransform: "uppercase", letterSpacing: 1.2, color: timeColor, marginBottom: 9 }}>{timeLabel}</div>
                      {timeSups.map(s => (
                        <div key={s.id} style={{ display: "flex", alignItems: "center", gap: 9, marginBottom: 9 }}>
                          <button onClick={() => setCustomSuppsDone(p => ({ ...p, [s.id]: !p[s.id] }))} style={{ width: 22, height: 22, borderRadius: 6, border: `1.5px solid ${customSuppsDone[s.id] ? C.dotGreen : C.border}`, background: customSuppsDone[s.id] ? "rgba(169,191,83,0.2)" : "transparent", color: C.dotGreen, fontSize: 12, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>{customSuppsDone[s.id] ? "✓" : ""}</button>
                          <div style={{ flex: 1 }}>
                            <div style={{ fontSize: 12, fontWeight: 600, color: customSuppsDone[s.id] ? C.sub : C.text, textDecoration: customSuppsDone[s.id] ? "line-through" : "none" }}>{s.name}</div>
                            {s.note && <div style={{ fontSize: 9, color: C.sub, marginTop: 1 }}>{s.note}</div>}
                          </div>
                          <button onClick={() => setSuppEditSheet(s.id)} style={{ fontSize: 14, color: C.muted, background: "none", border: "none", cursor: "pointer", padding: "0 2px" }}>···</button>
                        </div>
                      ))}
                      <div style={{ height: 1, background: C.border, margin: "8px 0 10px" }} />
                    </div>
                  );
                })}

                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginTop: 4, padding: "8px 10px", background: "rgba(192,132,160,0.08)", borderRadius: 8 }}>
                  <div style={{ fontSize: 10, color: C.sub }}>💊 Supplement streak</div>
                  <div style={{ fontSize: 14, fontWeight: 800, color: C.dotPurple }}>🔥 {suppStreak} days</div>
                </div>
                <button onClick={() => setShowAddSupp(true)} style={{ width: "100%", marginTop: 10, padding: 9, borderRadius: 9, border: "1px dashed C.border", background: "transparent", color: C.muted, fontSize: 11, cursor: "pointer", fontFamily: "inherit" }}>+ Add a supplement</button>
              </Card>

              {/* Archived routine */}
              <div style={{ padding: "2px 2px" }}>
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 0 8px", cursor: "pointer" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 11, fontWeight: 700, color: C.muted }}>
                    🗂️ Starter routine
                    <span style={{ fontSize: 9, background: "rgba(169,191,83,0.12)", color: C.dotGreen, borderRadius: 10, padding: "2px 8px", fontWeight: 700 }}>✓ Achieved</span>
                  </div>
                  <span style={{ fontSize: 10, color: C.muted }}>▼</span>
                </div>
                <div style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 11, padding: "11px 12px", opacity: 0.55 }}>
                  <div style={{ fontSize: 9, color: "#5a4a6a", fontWeight: 700, textTransform: "uppercase", letterSpacing: .8, marginBottom: 8 }}>Completed weeks 1–5</div>
                  {["Week 1 — D3+K2 + Omega-3","Week 2 — Added Magnesium","Week 3 — Added Vitamin C","Week 4 — Added Zinc + Collagen","Week 5 — Added B Complex"].map((w, i) => (
                    <div key={i} style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: i < 4 ? 7 : 0 }}>
                      <div style={{ width: 18, height: 18, borderRadius: 5, background: "rgba(169,191,83,0.15)", border: "1px solid rgba(169,191,83,0.3)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 10, color: C.dotGreen, flexShrink: 0 }}>✓</div>
                      <div style={{ fontSize: 11, color: "#7a5a8a" }}>{w}</div>
                    </div>
                  ))}
                </div>
              </div>
            </>
          ) : (
            /* Routine in progress */
            <Card>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
                <div style={{ fontSize: 12, fontWeight: 800, color: C.text }}>Week {suppRoutineWeek} of 5</div>
                <div style={{ display: "flex", gap: 6 }}>
                  {suppRoutineWeek < 5 && (
                    <button onClick={() => setSuppRoutineWeek(p => Math.min(5, p + 1))} style={{ fontSize: 9, color: C.sub, background: C.inputBg, border: `1px solid ${C.border}`, borderRadius: 6, padding: "3px 8px", cursor: "pointer", fontFamily: "inherit" }}>Next week →</button>
                  )}
                  {suppRoutineWeek === 5 && (
                    <button onClick={() => {
                      setSuppRoutineComplete(true);
                      const allSupps = SUPP_ROUTINE.map(s => ({ ...s, id: `routine-${s.name.replace(/\s/g,'')}` }));
                      setCustomSupps(allSupps);
                    }} style={{ fontSize: 9, color: C.dotGreen, background: "rgba(169,191,83,0.1)", border: `1px solid rgba(169,191,83,0.3)`, borderRadius: 6, padding: "3px 8px", cursor: "pointer", fontFamily: "inherit" }}>✓ Mark complete</button>
                  )}
                </div>
              </div>

              {["am","mid","pm"].map(time => {
                const active = SUPP_ROUTINE.filter(s => s.time === time && s.week <= suppRoutineWeek);
                const locked = SUPP_ROUTINE.filter(s => s.time === time && s.week > suppRoutineWeek);
                if (active.length === 0 && locked.length === 0) return null;
                const timeLabel = time === "am" ? "☀️ Morning" : time === "mid" ? "🌤️ Afternoon" : "🌙 Evening";
                const timeColor = time === "am" ? C.dotPink : time === "mid" ? C.dotBlue : C.plum;
                return (
                  <div key={time} style={{ marginBottom: 14 }}>
                    <div style={{ fontSize: 9, fontWeight: 800, textTransform: "uppercase", letterSpacing: 1.2, color: timeColor, marginBottom: 9 }}>{timeLabel}</div>
                    {active.map(s => (
                      <div key={s.name} style={{ display: "flex", alignItems: "center", gap: 9, marginBottom: 8 }}>
                        <button onClick={() => setSuppChecked && null} style={{ width: 22, height: 22, borderRadius: 6, border: `1.5px solid ${C.border}`, background: "transparent", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }} />
                        <div style={{ flex: 1 }}>
                          <div style={{ fontSize: 12, fontWeight: 600, color: C.text }}>{s.name}</div>
                          <div style={{ fontSize: 9, color: C.sub, marginTop: 1 }}>{s.note}</div>
                        </div>
                        <div style={{ fontSize: 9, fontWeight: 700, color: s.freq === "Daily" ? C.dotGreen : C.dotBlue, background: s.freq === "Daily" ? "rgba(169,191,83,0.1)" : "rgba(107,230,247,0.1)", borderRadius: 4, padding: "2px 6px", flexShrink: 0 }}>{s.freq}</div>
                      </div>
                    ))}
                    {locked.map(s => (
                      <div key={s.name} style={{ display: "flex", alignItems: "center", gap: 9, marginBottom: 8, opacity: 0.25 }}>
                        <div style={{ width: 22, height: 22, borderRadius: 6, border: "1.5px solid C.border", flexShrink: 0 }} />
                        <div style={{ flex: 1 }}>
                          <div style={{ fontSize: 12, fontWeight: 600, color: C.text }}>{s.name}</div>
                          <div style={{ fontSize: 9, color: C.sub }}>{s.note}</div>
                        </div>
                        <div style={{ fontSize: 9, fontWeight: 700, color: C.muted, background: C.inputBg, borderRadius: 4, padding: "2px 6px", flexShrink: 0 }}>Week {s.week}</div>
                      </div>
                    ))}
                    <div style={{ height: 1, background: C.border, margin: "6px 0 10px" }} />
                  </div>
                );
              })}

              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "8px 10px", background: "rgba(192,132,160,0.08)", borderRadius: 8 }}>
                <div style={{ fontSize: 10, color: C.sub }}>💊 Supplement streak</div>
                <div style={{ fontSize: 14, fontWeight: 800, color: C.dotPurple }}>🔥 {suppStreak} days</div>
              </div>
            </Card>
          )}

          {/* Add supplement form */}
          {showAddSupp && (
            <div style={{ position: "fixed", inset: 0, zIndex: 50, display: "flex", flexDirection: "column", justifyContent: "flex-end" }} onClick={() => setShowAddSupp(false)}>
              <div style={{ background: "#1e1228", borderRadius: "16px 16px 0 0", padding: "16px 14px 32px", border: `1px solid ${C.border}` }} onClick={e => e.stopPropagation()}>
                <div style={{ width: 36, height: 4, background: C.border, borderRadius: 2, margin: "0 auto 14px" }} />
                <div style={{ fontSize: 13, fontWeight: 800, color: C.text, marginBottom: 14 }}>Add supplement 💊</div>
                <input value={newSuppName} onChange={e => setNewSuppName(e.target.value)} placeholder="Name + dose (e.g. Vitamin D 2000 IU)" style={{ width: "100%", background: C.inputBg, border: `1px solid ${C.border}`, borderRadius: 9, padding: "9px 12px", color: C.text, fontSize: 13, fontFamily: "inherit", outline: "none", marginBottom: 10, boxSizing: "border-box" }} />
                <input value={newSuppNote} onChange={e => setNewSuppNote(e.target.value)} placeholder="Brand / note (optional)" style={{ width: "100%", background: C.inputBg, border: `1px solid ${C.border}`, borderRadius: 9, padding: "9px 12px", color: C.text, fontSize: 13, fontFamily: "inherit", outline: "none", marginBottom: 10, boxSizing: "border-box" }} />
                <div style={{ fontSize: 9, fontWeight: 800, textTransform: "uppercase", letterSpacing: 1, color: C.sub, marginBottom: 8 }}>Time of day</div>
                <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
                  {[["am","☀️ Morning"],["mid","🌤️ Afternoon"],["pm","🌙 Evening"]].map(([k,l]) => (
                    <button key={k} onClick={() => setNewSuppTime(k)} style={{ flex: 1, padding: "8px 4px", borderRadius: 8, border: newSuppTime === k ? `1.5px solid ${C.rose}` : `1px solid ${C.border}`, background: newSuppTime === k ? `${C.rose}18` : "transparent", color: newSuppTime === k ? C.rose : C.sub, fontSize: 10, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>{l}</button>
                  ))}
                </div>
                <button onClick={() => {
                  if (!newSuppName.trim()) return;
                  const s = { id: `s${Date.now()}`, name: newSuppName.trim(), note: newSuppNote.trim(), time: newSuppTime, freq: "Daily" };
                  setCustomSupps(p => [...p, s]);
                  setNewSuppName(""); setNewSuppNote(""); setNewSuppTime("am");
                  setShowAddSupp(false);
                }} style={{ width: "100%", padding: 10, borderRadius: 10, border: "none", background: C.rose, color: "#fff", fontSize: 13, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>Add supplement</button>
              </div>
            </div>
          )}

          {/* Supp edit sheet */}
          {suppEditSheet && (() => {
            const s = customSupps.find(x => x.id === suppEditSheet);
            if (!s) return null;
            return (
              <div style={{ position: "fixed", inset: 0, zIndex: 50, display: "flex", flexDirection: "column", justifyContent: "flex-end" }} onClick={() => setSuppEditSheet(null)}>
                <div style={{ background: "#1e1228", borderRadius: "16px 16px 0 0", padding: "16px 14px 32px", border: `1px solid ${C.border}` }} onClick={e => e.stopPropagation()}>
                  <div style={{ width: 36, height: 4, background: C.border, borderRadius: 2, margin: "0 auto 14px" }} />
                  <div style={{ fontSize: 13, fontWeight: 800, color: C.text, marginBottom: 4 }}>{s.name}</div>
                  <div style={{ fontSize: 9, color: C.sub, marginBottom: 16 }}>{s.note}</div>
                  {[
                    { icon: "⏸️", label: "Pause supplement", action: () => setSuppEditSheet(null) },
                    { icon: "🗑️", label: "Remove supplement", danger: true, action: () => { setCustomSupps(p => p.filter(x => x.id !== s.id)); setSuppEditSheet(null); } },
                  ].map((opt, i) => (
                    <button key={i} onClick={opt.action} style={{ width: "100%", display: "flex", alignItems: "center", gap: 12, padding: "11px 4px", background: "none", border: "none", borderBottom: i < 1 ? `1px solid ${C.border}` : "none", cursor: "pointer", color: opt.danger ? C.amber : C.text, fontFamily: "inherit", fontSize: 13 }}>
                      <span style={{ fontSize: 16, width: 24, textAlign: "center" }}>{opt.icon}</span>
                      {opt.label}
                    </button>
                  ))}
                </div>
              </div>
            );
          })()}
        </div>
      )}

      {/* ── CYCLE ── */}
      {pill === "cycle" && (
        <div style={{ padding: "4px 14px 24px" }}>
          {/* Phase hero with affirmation */}
          <div style={{ background: `linear-gradient(135deg, ${phase ? PHASE_INFO[phase].color : C.rose}12, rgba(107,170,196,0.06))`, border: `1px solid ${phase ? PHASE_INFO[phase].color : C.rose}30`, borderRadius: 14, padding: "16px", marginBottom: 10, textAlign: "center" }}>
            <div style={{ fontSize: 32, fontWeight: 800, color: phase ? PHASE_INFO[phase].color : C.rose }}>{dayOfCycle ? `Day ${dayOfCycle}` : "—"}</div>
            <div style={{ fontSize: 13, fontWeight: 700, color: C.plum, marginTop: 2 }}>{phase ? `${PHASE_INFO[phase].emoji} ${PHASE_INFO[phase].label}` : "Log your first period"}</div>
            <div style={{ fontSize: 12, color: C.text, fontStyle: "italic", marginTop: 10, padding: "10px 12px", background: C.surface, borderRadius: 10, lineHeight: 1.5 }}>"{todayAffirmation}"</div>
          </div>

          {/* Log period button */}
          <button onClick={() => setShowPeriodDialog(true)} style={{ width: "100%", padding: 12, borderRadius: 12, border: "none", background: C.rose, color: "#fff", fontSize: 13, fontWeight: 800, cursor: "pointer", marginBottom: 10, fontFamily: "inherit" }}>
            🩸 Log Period {isOnPeriod ? "(currently on period)" : ""}
          </button>

          {/* Category pills */}
          <div style={{ display: "flex", gap: 6, overflowX: "auto", marginBottom: 10, paddingBottom: 2 }}>
            {CYCLE_CATEGORIES.map(cat => (
              <button key={cat.id} onClick={() => setCycleCategory(cat.id)} style={{ flexShrink: 0, padding: "6px 12px", borderRadius: 16, fontSize: 10, fontWeight: 700, border: cycleCategory === cat.id ? "none" : `1.5px solid ${C.border}`, background: cycleCategory === cat.id ? C.rose : C.surface, color: cycleCategory === cat.id ? "#fff" : C.sub, cursor: "pointer", whiteSpace: "nowrap", fontFamily: "inherit" }}>{cat.emoji} {cat.label}</button>
            ))}
          </div>

          {/* Flat icon grid for active category */}
          <Card>
            <div style={{ fontSize: 9, fontWeight: 800, textTransform: "uppercase", letterSpacing: 1, color: C.muted, marginBottom: 10 }}>{activeCategory.label} today</div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 8 }}>
              {activeCategory.options.map(opt => {
                const sel = activeCategory.multi ? (todayCycle[activeCategory.id] || []).includes(opt.label) : todayCycle[activeCategory.id] === opt.label;
                return (
                  <div key={opt.label} onClick={() => toggleCycleOption(activeCategory.id, opt.label, activeCategory.multi)} style={{ textAlign: "center", cursor: "pointer" }}>
                    <div style={{ width: 52, height: 52, borderRadius: "50%", background: sel ? C.rose : C.inputBg, border: `1.5px solid ${sel ? C.rose : C.border}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22, margin: "0 auto 5px" }}>{opt.emoji}</div>
                    <div style={{ fontSize: 9, color: C.text, fontWeight: 600 }}>{opt.label}</div>
                  </div>
                );
              })}
            </div>
          </Card>

          {/* Next period prediction */}
          {nextPeriod && (
            <Card style={{ textAlign: "center" }}>
              <div style={{ fontSize: 9, color: C.muted, fontWeight: 700, textTransform: "uppercase", letterSpacing: 1, marginBottom: 6 }}>Next period predicted</div>
              <div style={{ fontSize: 18, fontWeight: 800, color: C.rose }}>{nextPeriod.toLocaleDateString("en-US", { month: "long", day: "numeric" })}</div>
              <div style={{ fontSize: 10, color: C.sub, marginTop: 3 }}>in {Math.max(0, Math.round((nextPeriod - new Date()) / 86400000))} days · avg cycle {AVG_CYCLE} days</div>
            </Card>
          )}

          {/* Start/End dialog */}
          {showPeriodDialog && (
            <div style={{ position: "fixed", inset: 0, zIndex: 50, display: "flex", alignItems: "center", justifyContent: "center", background: "rgba(0,0,0,0.3)" }} onClick={() => setShowPeriodDialog(false)}>
              <div style={{ background: C.surface, borderRadius: 16, padding: 20, width: 240, textAlign: "center" }} onClick={e => e.stopPropagation()}>
                <div style={{ fontSize: 14, fontWeight: 800, color: C.text, marginBottom: 4 }}>Log Period 🩸</div>
                <div style={{ fontSize: 11, color: C.sub, marginBottom: 16 }}>Is today the start or end?</div>
                <div style={{ display: "flex", gap: 8 }}>
                  <button onClick={() => { updateCycleToday({ periodEvent: "start" }); setShowPeriodDialog(false); }} style={{ flex: 1, padding: 10, borderRadius: 10, fontSize: 12, fontWeight: 700, border: "none", cursor: "pointer", background: C.rose, color: "#fff", fontFamily: "inherit" }}>Start</button>
                  <button onClick={() => { updateCycleToday({ periodEvent: "end" }); setShowPeriodDialog(false); }} style={{ flex: 1, padding: 10, borderRadius: 10, fontSize: 12, fontWeight: 700, border: "none", cursor: "pointer", background: C.border, color: C.plum, fontFamily: "inherit" }}>End</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function WeightTab({ weightLog, setWeightLog, measurements, setMeasurements }) {
  const latest = weightLog.length > 0 ? parseFloat(weightLog[0].weight) : START_WEIGHT;
  const lost = +(START_WEIGHT - latest).toFixed(1);
  const remaining = +(latest - GOAL_WEIGHT).toFixed(1);
  const pct = Math.min(100, Math.max(0, Math.round(((START_WEIGHT - latest) / (START_WEIGHT - GOAL_WEIGHT)) * 100)));
  const td = calcTargetDate(latest);
  const r = 38; const circ = 2 * Math.PI * r;
  return (
    <div style={{ padding: "16px 14px 24px" }}>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 14 }}>
        {[
          { label: "Current", val: `${latest}`, unit: "lbs", color: "#e0c8f0" },
          { label: "Lost", val: `${lost > 0 ? lost : 0}`, unit: "lbs", color: C.rose },
          { label: "To go", val: `${remaining > 0 ? remaining : 0}`, unit: "lbs", color: C.amber },
        ].map(s => (
          <div key={s.label} style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12, padding: "12px 8px", textAlign: "center" }}>
            <div style={{ fontSize: 9, color: C.sub, fontWeight: 700, textTransform: "uppercase", letterSpacing: .5, marginBottom: 5 }}>{s.label}</div>
            <div style={{ fontSize: 20, fontWeight: 800, color: s.color, lineHeight: 1 }}>{s.val}</div>
            <div style={{ fontSize: 9, color: C.sub, marginTop: 2 }}>{s.unit}</div>
          </div>
        ))}
      </div>
      <Card style={{ display: "flex", gap: 14, alignItems: "center" }}>
        <svg width="96" height="96" viewBox="0 0 96 96" style={{ flexShrink: 0 }}>
          <circle cx="48" cy="48" r={r} fill="none" stroke={C.inputBg} strokeWidth="8"/>
          <circle cx="48" cy="48" r={r} fill="none" stroke={C.rose} strokeWidth="8"
            strokeDasharray={circ} strokeDashoffset={circ * (1 - pct / 100)} strokeLinecap="round"
            transform="rotate(-90 48 48)"/>
          <text x="48" y="44" textAnchor="middle" fontSize="16" fontWeight="800" fill="#e0c8f0">{pct}%</text>
          <text x="48" y="57" textAnchor="middle" fontSize="9" fill={C.sub}>progress</text>
        </svg>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: "#e0c8f0", marginBottom: 4 }}>Goal: {GOAL_WEIGHT} lbs</div>
          {td ? <>
            <div style={{ fontSize: 10, color: C.sub, marginBottom: 2 }}>Estimated date</div>
            <div style={{ fontSize: 15, fontWeight: 700, color: C.amber }}>{fmtDate(td)}</div>
            <div style={{ fontSize: 10, color: C.sub, marginTop: 2 }}>{weeksAway(td)}</div>
          </> : <div style={{ fontSize: 10, color: C.sub }}>Log more weight to see estimate</div>}
        </div>
      </Card>
      <Card><WeightSection weightLog={weightLog} setWeightLog={setWeightLog} /></Card>
      <Card>
        <SectionLabel>Body measurements</SectionLabel>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
          {Object.keys(measurements).map(key => (
            <div key={key}>
              <div style={{ fontSize: 9, color: C.sub, textTransform: "uppercase", letterSpacing: .5, marginBottom: 4 }}>{key} (in)</div>
              <input type="number" value={measurements[key]} onChange={e => setMeasurements(p => ({ ...p, [key]: e.target.value }))} placeholder="—"
                style={{ width: "100%", background: C.inputBg, border: `1px solid ${C.border}`, borderRadius: 8, padding: "7px 10px", color: C.text, fontSize: 13, fontFamily: "inherit", outline: "none", boxSizing: "border-box" }} />
            </div>
          ))}
        </div>
      </Card>
      <Card accent={C.plum}>
        <SectionLabel>📸 Progress Photo Reminder</SectionLabel>
        <div style={{ fontSize: 11, color: C.sub, lineHeight: 1.7 }}>Every <span style={{ color: "#d0c0e0" }}>2–4 weeks</span> — same lighting, same pose, same time of day. The mirror lies. Photos reveal what the scale never will.</div>
      </Card>
    </div>
  );
}

function PlanTab({ weeklyWorkouts }) {
  const [expandedDay, setExpandedDay] = useState(null);
  return (
    <div style={{ padding: "16px 14px 24px" }}>
      <div style={{ fontSize: 16, fontWeight: 800, color: C.text, marginBottom: 4 }}>Your Week 🏹</div>
      <div style={{ fontSize: 10, color: C.sub, marginBottom: 16 }}>5-day strength + recovery plan · tap a day to see exercises</div>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 9, marginBottom: 9 }}>
        {DAYS.slice(0, 4).map(d => {
          const done = weeklyWorkouts[d.id];
          const isOpen = expandedDay === d.id;
          return (
            <div key={d.id} onClick={() => setExpandedDay(isOpen ? null : d.id)} style={{ background: done ? `${d.color}12` : C.surface, border: `1.5px solid ${isOpen ? d.color : done ? `${d.color}40` : C.border}`, borderRadius: 14, padding: 13, cursor: "pointer" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 8 }}>
                <div style={{ fontSize: 8, fontWeight: 800, color: done ? d.color : C.muted, textTransform: "uppercase", letterSpacing: .5 }}>Day {d.id}</div>
                {done && <div style={{ fontSize: 10, color: d.color }}>✓</div>}
              </div>
              <div style={{ fontSize: 13, fontWeight: 800, color: C.text, marginBottom: 3 }}>{d.label.replace(`Day ${d.id} — `, "")}</div>
              <div style={{ fontSize: 9, color: C.sub, marginBottom: 8 }}>{d.focus}</div>
              <div style={{ display: "flex", gap: 3 }}>
                {d.exercises.slice(0, 5).map((_, i) => (
                  <div key={i} style={{ width: 6, height: 6, borderRadius: "50%", background: done ? d.color : C.border }} />
                ))}
              </div>
              {isOpen && (
                <div style={{ marginTop: 10, paddingTop: 10, borderTop: `1px solid ${C.border}` }}>
                  {d.exercises.map(ex => (
                    <div key={ex.id} style={{ display: "flex", justifyContent: "space-between", padding: "4px 0", borderBottom: `1px solid ${C.surface}`, fontSize: 11 }}>
                      <span style={{ color: "#d0c0e0" }}>{ex.name}</span>
                      <span style={{ color: C.muted, fontSize: 10 }}>{ex.sets > 1 ? `${ex.sets}×${ex.reps}` : ex.reps}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>
      {DAYS.slice(4).map(d => {
        const done = weeklyWorkouts[d.id];
        const isOpen = expandedDay === d.id;
        return (
          <div key={d.id} onClick={() => setExpandedDay(isOpen ? null : d.id)} style={{ background: done ? `${d.color}12` : C.surface, border: `1.5px solid ${isOpen ? d.color : done ? `${d.color}40` : C.border}`, borderRadius: 14, padding: 13, cursor: "pointer", marginBottom: 9 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
              <div style={{ fontSize: 8, fontWeight: 800, color: done ? d.color : C.muted, textTransform: "uppercase", letterSpacing: .5 }}>Day {d.id} · {d.isRecovery ? "Recovery" : "Finisher"}</div>
              {done && <div style={{ fontSize: 10, color: d.color }}>✓ Complete</div>}
            </div>
            <div style={{ fontSize: 14, fontWeight: 800, color: C.text, marginBottom: 3 }}>{d.label.replace(`Day ${d.id} — `, "")} {d.isRecovery ? "🌿" : "🔥"}</div>
            <div style={{ fontSize: 9, color: C.sub }}>{d.focus}</div>
            {isOpen && (
              <div style={{ marginTop: 10, paddingTop: 10, borderTop: `1px solid ${C.border}` }}>
                {d.exercises.map(ex => (
                  <div key={ex.id} style={{ display: "flex", justifyContent: "space-between", padding: "4px 0", borderBottom: `1px solid ${C.surface}`, fontSize: 11 }}>
                    <span style={{ color: "#d0c0e0" }}>{ex.name}</span>
                    <span style={{ color: C.muted, fontSize: 10 }}>{ex.sets > 1 ? `${ex.sets}×${ex.reps}` : ex.reps}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

function WorkoutExerciseCard({ ex, exKey, done, dayColor, checkEx }) {
  const [setsDone, setSetsDone] = useState(() => loadS(`sets-${exKey}`, []));
  const totalSets = ex.sets;
  const doneSetCount = setsDone.length;

  const toggleSet = (i) => {
    let next;
    if (setsDone.includes(i)) next = setsDone.filter(x => x !== i);
    else next = [...setsDone, i];
    setSetsDone(next);
    saveS(`sets-${exKey}`, next);
    if (totalSets > 1) {
      if (next.length >= totalSets) checkEx(exKey, true);
      else checkEx(exKey, false);
    }
  };

  return (
    <div style={{ background: done ? `${C.dotGreen}12` : C.surface, border: `1px solid ${done ? `${C.dotGreen}40` : C.border}`, borderRadius: 13, padding: "12px 13px", marginBottom: 8 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <div style={{ width: 38, height: 38, borderRadius: 11, background: done ? `${C.dotGreen}22` : `${dayColor}18`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>{done ? "✓" : "🏋️"}</div>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: done ? C.sub : C.text, textDecoration: done ? "line-through" : "none" }}>{ex.name}</div>
          <div style={{ fontSize: 9, color: C.sub, marginTop: 2 }}>
            {ex.sets > 1 ? `${ex.sets} sets × ${ex.reps}` : ex.reps}{ex.weight ? ` · ${ex.weight}` : ""}
            {ex.sets > 1 && <span style={{ color: dayColor, marginLeft: 6, fontWeight: 700 }}>{doneSetCount}/{ex.sets} done</span>}
          </div>
        </div>
        {ex.sets <= 1 && (
          <button className="check-anim" onClick={() => checkEx(exKey, !done)} style={{ width: 34, height: 34, borderRadius: 9, border: `1.5px solid ${done ? `${C.dotGreen}80` : C.border}`, background: done ? `${C.dotGreen}22` : "transparent", color: done ? C.dotGreen : C.muted, fontSize: 14, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, fontFamily: "inherit", transition: "transform 0.15s, background 0.15s" }}>{done ? "✓" : "○"}</button>
        )}
      </div>
      {ex.sets > 1 && (
        <div style={{ display: "flex", gap: 6, marginTop: 10, alignItems: "center", flexWrap: "wrap" }}>
          <div style={{ fontSize: 9, color: C.sub, marginRight: 2 }}>Sets:</div>
          {Array.from({ length: ex.sets }).map((_, i) => {
            const setChecked = setsDone.includes(i);
            return (
              <button key={i} className="check-anim" onClick={() => toggleSet(i)} style={{ width: 30, height: 30, borderRadius: 8, background: setChecked ? `${C.dotGreen}22` : C.inputBg, border: `1.5px solid ${setChecked ? C.dotGreen : C.border}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, color: setChecked ? C.dotGreen : C.muted, fontWeight: 700, cursor: "pointer", fontFamily: "inherit", transition: "all 0.15s" }}>
                {setChecked ? "✓" : i + 1}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

function WorkoutTab({ selectedDay, setSelectedDay, checked, checkEx, weeklyWorkouts, markDayDone, day, pct, doneCount, exKeys }) {
  const photo = DAY_PHOTOS[selectedDay];
  return (
    <div>
      {/* Photo banner */}
      {photo && (
        <div style={{ position: "relative", height: 220, overflow: "hidden" }}>
          <img src={photo.src} alt="inspo" style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: photo.pos, display: "block" }} />
          <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 80, background: "linear-gradient(to bottom, rgba(19,13,26,0.75) 0%, transparent 100%)" }} />
          <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, height: 130, background: "linear-gradient(to top, rgba(19,13,26,1) 0%, rgba(19,13,26,0.6) 60%, transparent 100%)" }} />
          <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, padding: "0 16px 14px" }}>
            <div style={{ fontSize: 9, fontWeight: 800, color: day.color, textTransform: "uppercase", letterSpacing: 2, marginBottom: 4 }}>Day {selectedDay} · {day.focus}</div>
            <div style={{ fontSize: 17, fontWeight: 800, color: "#fff", marginBottom: 8 }}>{day.label.replace(`Day ${selectedDay} — `, "")} {day.isRecovery ? "🌿" : "💪"}</div>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div style={{ flex: 1, height: 4, borderRadius: 2, background: C.border, overflow: "hidden" }}>
                <div style={{ height: "100%", width: `${pct}%`, borderRadius: 2, background: day.color }} />
              </div>
              <div style={{ fontSize: 10, fontWeight: 700, color: day.color }}>{doneCount}/{exKeys.length} done</div>
            </div>
          </div>
        </div>
      )}
      <div style={{ padding: "14px 14px" }}>
        {/* Day strip */}
        <div style={{ display: "flex", gap: 6, marginBottom: 14, overflowX: "auto" }}>
          {DAYS.map(d => (
            <button key={d.id} onClick={() => setSelectedDay(d.id)} style={{ flexShrink: 0, padding: "7px 14px", borderRadius: 10, fontSize: 10, fontWeight: 700, cursor: "pointer", border: selectedDay === d.id ? `1.5px solid ${d.color}` : "1.5px solid C.border", background: weeklyWorkouts[d.id] ? `${d.color}18` : selectedDay === d.id ? `${d.color}12` : C.surface, color: selectedDay === d.id ? d.color : weeklyWorkouts[d.id] ? d.color : C.muted, fontFamily: "inherit" }}>
              {weeklyWorkouts[d.id] ? "✓" : d.id}
            </button>
          ))}
        </div>
        {/* Exercise cards */}
        {day.exercises.map(ex => {
          const key = `${selectedDay}-${ex.id}`;
          const done = !!checked[key];
          return <WorkoutExerciseCard key={ex.id} ex={ex} exKey={key} done={done} dayColor={day.color} checkEx={checkEx} />;
        })}
        {pct === 100 && !weeklyWorkouts[selectedDay] && (
          <button onClick={markDayDone} style={{ width: "100%", marginTop: 6, padding: 12, borderRadius: 12, border: "none", background: `linear-gradient(135deg, ${day.color}, #A07CC0)`, color: "#fff", fontSize: 14, fontWeight: 800, cursor: "pointer", fontFamily: "inherit" }}>🔥 Mark Day {selectedDay} Complete</button>
        )}
        {weeklyWorkouts[selectedDay] && (
          <div style={{ textAlign: "center", color: day.color, fontSize: 12, fontWeight: 700, padding: "12px 0" }}>✓ Day {selectedDay} logged this week!</div>
        )}
      </div>
    </div>
  );
}

function NutritionTab({ foodLog, setFoodLog, foodTotals, junkDelay, markTodayDots }) {
  const hasJunkToday = foodLog.some(f => f.category === "junk");
  useEffect(() => {
    if (foodLog.length > 0) {
      markTodayDots && markTodayDots({ noJunk: !hasJunkToday, nutrition: true });
    }
  }, [foodLog]);
  return (
    <div style={{ padding: "14px 14px 24px" }}>
      {/* Macro rings */}
      <Card>
        <SectionLabel>Today's nutrition</SectionLabel>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
          {[
            { label: "🥩 Protein", val: foodTotals.protein, goal: PROTEIN_GOAL, unit: "g", color: C.sage },
            { label: "🔥 Calories", val: foodTotals.calories, goal: CALORIE_GOAL, unit: "", color: C.amber },
            { label: "🫙 Carbs", val: foodTotals.carbs || 0, goal: 150, unit: "g", color: C.plum },
            { label: "🫒 Fat", val: foodTotals.fat || 0, goal: 55, unit: "g", color: "#8B7CC0" },
          ].map(({ label, val, goal, unit, color }) => (
            <div key={label} style={{ background: C.surface, border: `1px solid ${C.border}`, borderRadius: 10, padding: "10px 12px" }}>
              <div style={{ fontSize: 9, color: C.sub, fontWeight: 700, textTransform: "uppercase", letterSpacing: .5, marginBottom: 5 }}>{label}</div>
              <div style={{ fontSize: 18, fontWeight: 800, color }}>{val}<span style={{ fontSize: 10, color: C.sub, fontWeight: 400 }}>{unit}</span></div>
              <div style={{ height: 4, borderRadius: 2, background: C.border, margin: "6px 0 3px", overflow: "hidden" }}>
                <div style={{ height: "100%", width: `${Math.min(100, Math.round((val/goal)*100))}%`, background: color, borderRadius: 2 }} />
              </div>
              <div style={{ fontSize: 9, color: C.sub }}>{Math.min(100, Math.round((val/goal)*100))}% of {goal}{unit}</div>
            </div>
          ))}
        </div>
      </Card>

      {junkDelay > 0 && (
        <Card accent={C.amber}>
          <div style={{ fontSize: 12, color: C.amber, fontWeight: 700, marginBottom: 4 }}>⚠️ Junk food impact</div>
          <div style={{ fontSize: 11, color: C.sub }}>Today's junk food adds ~{junkDelay} days to your goal date.</div>
        </Card>
      )}

      {/* Food logger */}
      <FoodLogger foodLog={foodLog} setFoodLog={setFoodLog} />
    </div>
  );
}

export default function FitnessTracker() {
  const todayKey = getTodayKey();
  const weekKey = getWeekKey();
  const [synced, setSynced] = useState(false);
  const [activeTab, setActiveTab] = useState("home");
  const [selectedDay, setSelectedDay] = useState(1);
  const [checked, setChecked] = useState(() => loadS(`ex-${todayKey}`, {}));
  const [weeklyWorkouts, setWeeklyWorkouts] = useState(() => loadS(`wkly-${weekKey}`, {}));
  const [weightLog, setWeightLog] = useState(() => loadS("weight-log", []));
  const [foodLog, setFoodLog] = useState(() => loadS(`food-${todayKey}`, []));
  const [dailyStats, setDailyStats] = useState(() => loadS(`stats-${todayKey}`, { steps: 0, water: 0, sleep: 0 }));
  const [waterTaps, setWaterTaps] = useState(() => loadS(`water-${todayKey}`, 0));
  const [supplements, setSupplements] = useState(() => loadS("supplements-list", []));
  const [suppChecked, setSuppChecked] = useState(() => loadS(`supp-${todayKey}`, {}));
  const [weeklyHistory, setWeeklyHistory] = useState(() => loadS("weekly-history", {}));
  const [splurgeRewards, setSplurgeRewards] = useState(() => loadS("splurge-rewards", { "7": "", "30": "", "90": "" }));
  const [measurements, setMeasurements] = useState(() => loadS("body-measurements", { waist: "", hips: "", arms: "", thighs: "" }));
  const [junkDelay, setJunkDelay] = useState(0);
  const [habits, setHabits] = useState(() => loadS("habits-list", [
    { id: "h1", name: "No phone before bed", emoji: "🌙", color: "rgba(192,132,160,0.15)", streak: 0, lastDone: "" },
    { id: "h2", name: "Skincare routine", emoji: "🧴", color: "rgba(160,124,192,0.15)", streak: 0, lastDone: "" },
    { id: "h3", name: "Journal / gratitude", emoji: "📓", color: "rgba(123,191,160,0.15)", streak: 0, lastDone: "" },
  ]));
  const [habitsDone, setHabitsDone] = useState(() => loadS(`habits-done-${todayKey}`, {}));
  const [cycleLog, setCycleLog] = useState(() => loadS("cycle-log", {}));
  const [suppRoutineWeek, setSuppRoutineWeek] = useState(() => loadS("supp-routine-week", 1));
  const [suppRoutineComplete, setSuppRoutineComplete] = useState(() => loadS("supp-routine-complete", false));
  const [customSupps, setCustomSupps] = useState(() => loadS("custom-supps", []));
  const [customSuppsDone, setCustomSuppsDone] = useState(() => loadS(`custom-supps-done-${todayKey}`, {}));
  const [showMore, setShowMore] = useState(false);

  useEffect(() => {
    runAutoResets();
    supaLoad().then(() => {
      setSynced(true);
      setWeightLog(loadS("weight-log", []));
      setFoodLog(loadS(`food-${todayKey}`, []));
      setDailyStats(loadS(`stats-${todayKey}`, { steps: 0, water: 0, sleep: 0 }));
      setWaterTaps(loadS(`water-${todayKey}`, 0));
      setWeeklyHistory(loadS("weekly-history", {}));
      setWeeklyWorkouts(loadS(`wkly-${weekKey}`, {}));
      setChecked(loadS(`ex-${todayKey}`, {}));
      setHabits(loadS("habits-list", [
        { id: "h1", name: "No phone before bed", emoji: "🌙", color: "rgba(192,132,160,0.15)", streak: 0, lastDone: "" },
        { id: "h2", name: "Skincare routine", emoji: "🧴", color: "rgba(160,124,192,0.15)", streak: 0, lastDone: "" },
        { id: "h3", name: "Journal / gratitude", emoji: "📓", color: "rgba(123,191,160,0.15)", streak: 0, lastDone: "" },
      ]));
      setCycleLog(loadS("cycle-log", {}));
      setSuppRoutineWeek(loadS("supp-routine-week", 1));
      setSuppRoutineComplete(loadS("supp-routine-complete", false));
      setCustomSupps(loadS("custom-supps", []));
      setMeasurements(loadS("body-measurements", { waist: "", hips: "", arms: "", thighs: "" }));
      setSplurgeRewards(loadS("splurge-rewards", { "7": "", "30": "", "90": "" }));
    });
  }, []);

  useEffect(() => { saveS(`ex-${todayKey}`, checked); }, [checked]);
  useEffect(() => { saveS(`wkly-${weekKey}`, weeklyWorkouts); }, [weeklyWorkouts]);
  useEffect(() => { saveS("weight-log", weightLog); }, [weightLog]);
  useEffect(() => { saveS(`food-${todayKey}`, foodLog); }, [foodLog]);
  useEffect(() => { saveS(`stats-${todayKey}`, dailyStats); }, [dailyStats]);
  useEffect(() => { saveS(`water-${todayKey}`, waterTaps); }, [waterTaps]);
  useEffect(() => { saveS(`supp-${todayKey}`, suppChecked); }, [suppChecked]);
  useEffect(() => { saveS("weekly-history", weeklyHistory); }, [weeklyHistory]);
  useEffect(() => { saveS("splurge-rewards", splurgeRewards); }, [splurgeRewards]);
  useEffect(() => { saveS("body-measurements", measurements); }, [measurements]);
  useEffect(() => { saveS("habits-list", habits); }, [habits]);
  useEffect(() => { saveS(`habits-done-${todayKey}`, habitsDone); }, [habitsDone]);
  useEffect(() => { saveS("cycle-log", cycleLog); }, [cycleLog]);
  useEffect(() => { saveS("supp-routine-week", suppRoutineWeek); }, [suppRoutineWeek]);
  useEffect(() => { saveS("supp-routine-complete", suppRoutineComplete); }, [suppRoutineComplete]);
  useEffect(() => { saveS("custom-supps", customSupps); }, [customSupps]);
  useEffect(() => { saveS(`custom-supps-done-${todayKey}`, customSuppsDone); }, [customSuppsDone]);
  useEffect(() => {
    const delay = foodLog.filter(f => f.category === "junk").reduce((s, f) => s + (f.delayDays || 0), 0);
    setJunkDelay(+delay.toFixed(1));
  }, [foodLog]);

  const day = DAYS.find(d => d.id === selectedDay);
  const exKeys = day.exercises.map(e => `${selectedDay}-${e.id}`);
  const doneCount = exKeys.filter(k => checked[k]).length;
  const pct = exKeys.length ? Math.round((doneCount / exKeys.length) * 100) : 0;
  const waterOz = waterTaps * 8;
  const foodTotals = foodLog.reduce((a, f) => ({ protein: a.protein + (f.protein||0), calories: a.calories + (f.calories||0), carbs: a.carbs + (f.carbs||0), fat: a.fat + (f.fat||0) }), { protein: 0, calories: 0, carbs: 0, fat: 0 });

  const checkEx = (key, val) => setChecked(prev => ({ ...prev, [key]: val }));
  const markTodayDots = (extra = {}) => {
    const today = getTodayKey();
    const existing = weeklyHistory[today] || {};
    const updated = { ...weeklyHistory, [today]: { ...existing, ...extra } };
    setWeeklyHistory(updated);
    saveS("weekly-history", updated);
  };
  const markDayDone = () => {
    setWeeklyWorkouts(prev => ({ ...prev, [selectedDay]: true }));
    markTodayDots({ workout: true });
  };
  const resetWeekManual = () => {
    setWeeklyWorkouts({});
    setChecked({});
    saveS(`wkly-${weekKey}`, {});
    saveS(`ex-${todayKey}`, {});
  };

  const BOTTOM_NAV = [
    { k: "home", emoji: "🪬", label: "Home" },
    { k: "today", emoji: "🎀", label: "Workout" },
    { k: "nutrition", emoji: "🍒", label: "Nutrition" },
    { k: "habits", emoji: "💐", label: "Habits" },
    { k: "streak", emoji: "✴️", label: "Streak" },
  ];
  const MORE_TABS = [
    { k: "weight", emoji: "🫧", label: "Weight" },
    { k: "yoga", emoji: "🪷", label: "Yoga" },
  ];
  const isMoreTab = MORE_TABS.some(t => t.k === activeTab);

  return (
    <div style={{ fontFamily: "'Poppins','Segoe UI',sans-serif", background: C.bg, color: C.text, position: "fixed", top: 0, left: 0, right: 0, bottom: 0, maxWidth: 500, margin: "0 auto", display: "flex", flexDirection: "column", overflow: "hidden" }}>

      {/* Fixed Header */}
      <div style={{ padding: "14px 20px 10px", borderBottom: `1px solid ${C.border}`, display: "flex", alignItems: "center", justifyContent: "space-between", flexShrink: 0, background: C.bg, zIndex: 30 }}>
        <div>
          <div style={{ fontSize: 18, fontWeight: 800, letterSpacing: "-0.5px" }}>Soft Life, Hard Work <span style={{ color: C.dotPurple }}>❀</span></div>
          <div style={{ fontSize: 10, color: C.muted, marginTop: 2 }}>Strength · Recovery · Yoga · TOS Care</div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{ fontSize: 9, color: synced ? C.dotGreen : C.muted, display: "flex", alignItems: "center", gap: 4 }}>
            <div style={{ width: 6, height: 6, borderRadius: "50%", background: synced ? C.dotGreen : C.muted }} />
            {synced ? "Synced" : "Syncing…"}
          </div>
          <button onClick={resetWeekManual} style={{ fontSize: 10, color: C.muted, background: "transparent", border: `1px solid ${C.border}`, borderRadius: 8, padding: "5px 10px", cursor: "pointer", flexShrink: 0 }}>🔄</button>
        </div>
      </div>

      {/* More drawer */}
      {showMore && (
        <div style={{ position: "fixed", inset: 0, zIndex: 50, display: "flex", flexDirection: "column", justifyContent: "flex-end" }} onClick={() => setShowMore(false)}>
          <div style={{ background: "#1a0f24", borderRadius: "18px 18px 0 0", padding: "16px 20px 32px", border: `1px solid ${C.border}` }} onClick={e => e.stopPropagation()}>
            <div style={{ width: 36, height: 4, background: C.border, borderRadius: 2, margin: "0 auto 16px" }} />
            <div style={{ fontSize: 11, fontWeight: 800, color: C.sub, textTransform: "uppercase", letterSpacing: 1, marginBottom: 12 }}>More</div>
            {MORE_TABS.map(t => (
              <button key={t.k} onClick={() => { setActiveTab(t.k); setShowMore(false); }} style={{ width: "100%", display: "flex", alignItems: "center", gap: 14, padding: "13px 4px", background: "none", border: "none", borderBottom: `1px solid ${C.border}`, cursor: "pointer", color: activeTab === t.k ? C.rose : C.text, fontFamily: "inherit" }}>
                <span style={{ fontSize: 20 }}>{t.emoji}</span>
                <span style={{ fontSize: 14, fontWeight: 700 }}>{t.label}</span>
                {activeTab === t.k && <span style={{ marginLeft: "auto", fontSize: 10, color: C.rose }}>●</span>}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Scrollable content */}
      <div style={{ flex: 1, overflowY: "auto", WebkitOverflowScrolling: "touch" }}>
        {activeTab === "home" && <HomeTab weeklyWorkouts={weeklyWorkouts} weeklyHistory={weeklyHistory} foodTotals={foodTotals} waterOz={waterOz} dailyStats={dailyStats} weightLog={weightLog} setActiveTab={setActiveTab} />}
        {activeTab === "streak" && <StreakTab weeklyHistory={weeklyHistory} weightLog={weightLog} splurgeRewards={splurgeRewards} setSplurgeRewards={setSplurgeRewards} />}
        {activeTab === "habits" && <HabitsTab waterTaps={waterTaps} setWaterTaps={setWaterTaps} dailyStats={dailyStats} setDailyStats={setDailyStats} habits={habits} setHabits={setHabits} habitsDone={habitsDone} setHabitsDone={setHabitsDone} cycleLog={cycleLog} setCycleLog={setCycleLog} suppRoutineWeek={suppRoutineWeek} setSuppRoutineWeek={setSuppRoutineWeek} suppRoutineComplete={suppRoutineComplete} setSuppRoutineComplete={setSuppRoutineComplete} customSupps={customSupps} setCustomSupps={setCustomSupps} customSuppsDone={customSuppsDone} setCustomSuppsDone={setCustomSuppsDone} />}
        {activeTab === "weight" && <WeightTab weightLog={weightLog} setWeightLog={setWeightLog} measurements={measurements} setMeasurements={setMeasurements} />}
        {activeTab === "yoga" && <YogaTab markTodayDots={markTodayDots} />}

        {activeTab === "today" && <WorkoutTab selectedDay={selectedDay} setSelectedDay={setSelectedDay} checked={checked} checkEx={checkEx} weeklyWorkouts={weeklyWorkouts} markDayDone={markDayDone} day={day} pct={pct} doneCount={doneCount} exKeys={exKeys} />}
        {activeTab === "nutrition" && <NutritionTab foodLog={foodLog} setFoodLog={setFoodLog} foodTotals={foodTotals} junkDelay={junkDelay} markTodayDots={markTodayDots} />}
        
      </div>

      {/* Fixed Bottom nav */}
      <div style={{ background: "rgba(10,6,18,0.97)", borderTop: `1px solid ${C.border}`, display: "flex", zIndex: 40, paddingBottom: 8, flexShrink: 0 }}>
        {BOTTOM_NAV.map(t => (
          <button key={t.k} onClick={() => { setActiveTab(t.k); setShowMore(false); }} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 3, padding: "8px 0 4px", background: "none", border: "none", cursor: "pointer", fontFamily: "inherit" }}>
            <span style={{ fontSize: 20, lineHeight: 1 }}>{t.emoji}</span>
            <span style={{ fontSize: 8, fontWeight: 700, color: activeTab === t.k ? C.rose : C.muted }}>{t.label}</span>
            {activeTab === t.k && <div style={{ width: 4, height: 4, borderRadius: "50%", background: C.rose }} />}
          </button>
        ))}
        <button onClick={() => setShowMore(p => !p)} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 3, padding: "8px 0 4px", background: "none", border: "none", cursor: "pointer", fontFamily: "inherit" }}>
          <div style={{ width: 22, height: 22, borderRadius: "50%", background: C.border, border: `1px solid ${C.border}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, color: isMoreTab ? C.rose : C.muted }}>···</div>
          <span style={{ fontSize: 8, fontWeight: 700, color: isMoreTab ? C.rose : C.muted }}>More</span>
          {isMoreTab && <div style={{ width: 4, height: 4, borderRadius: "50%", background: C.rose }} />}
        </button>
      </div>
    </div>
  );
}
